function getCurrentUserPermissions() {
    if (!currentUser || !currentUser.user_permissions || typeof currentUser.user_permissions !== 'object') {
        return {};
    }
    return currentUser.user_permissions;
}

function userHasPermission(permissionKey, fallbackDepartment = null) {
    if (!currentUser) return false;
    if (currentUser.role === 'admin') return true;

    const permissions = getCurrentUserPermissions();
    if (permissions[permissionKey] === true) return true;

    if (fallbackDepartment && Array.isArray(currentUser.departments_access)) {
        return currentUser.departments_access.includes(fallbackDepartment);
    }

    return false;
}

function ensurePermission(permissionKey, errorText, fallbackDepartment = null) {
    if (userHasPermission(permissionKey, fallbackDepartment)) return true;
    showError(errorText || 'Недостаточно прав для выполнения действия');
    return false;
}

function collectUserPermissionsFromForm(selector = 'input[name="permissions"]:checked') {
    const checked = document.querySelectorAll(selector);
    const permissions = {};
    checked.forEach((input) => {
        if (input instanceof HTMLInputElement && input.value) {
            permissions[input.value] = true;
        }
    });
    return permissions;
}

function renderPermissionsEditor(selectedPermissions = {}) {
    const allKeys = getAllPermissionKeys();
    const viewOnlyKeys = allKeys.filter((key) => key.endsWith('.view'));
    const allKeysPayload = encodeURIComponent(JSON.stringify(allKeys));
    const viewOnlyPayload = encodeURIComponent(JSON.stringify(viewOnlyKeys));

    const groupsHtml = CRM_PERMISSION_GROUPS.map((group) => {
        const rows = group.permissions.map((p) => `
            <label class="permission-item">
                <input type="checkbox" name="permissions" value="${p.key}" ${selectedPermissions[p.key] ? 'checked' : ''}>
                <span class="permission-indicator" aria-hidden="true"></span>
                <span class="permission-text">
                    <span class="permission-label">${p.label}</span>
                    <span class="permission-key">${p.key}</span>
                </span>
            </label>
        `).join('');

        return `
            <div class="permission-group">
                <div class="permission-group-title">${group.title}</div>
                <div class="permission-grid">${rows}</div>
            </div>
        `;
    }).join('');

    return `
        <div class="permission-tools permission-tools-global">
            <button type="button" class="btn btn-secondary btn-small" onclick="applyPermissionQuickPreset(this, 'all', '${allKeysPayload}')">Выбрать все</button>
            <button type="button" class="btn btn-secondary btn-small" onclick="applyPermissionQuickPreset(this, 'none')">Снять все</button>
            <button type="button" class="btn btn-secondary btn-small" onclick="applyPermissionQuickPreset(this, 'view', '${viewOnlyPayload}')">Только просмотр</button>
        </div>
        ${groupsHtml}
    `;
}

function getAllPermissionKeys() {
    return CRM_PERMISSION_GROUPS.flatMap((g) => g.permissions.map((p) => p.key));
}

function getDefaultPermissionPresetForRole(role, departments = []) {
    if (role === 'admin') {
        return getAllPermissionKeys().reduce((acc, key) => {
            acc[key] = true;
            return acc;
        }, {});
    }

    const preset = { 'dashboard.view': true, 'archive.view': true };
    const deps = Array.isArray(departments) ? departments : [];
    if (deps.includes('warehouse')) preset['warehouse.view'] = true;
    if (deps.includes('recipes')) preset['recipes.view'] = true;
    if (deps.includes('orders')) preset['orders.view'] = true;
    if (deps.includes('production')) preset['production.view'] = true;
    if (deps.includes('shift-schedule')) preset['shift_schedule.view'] = true;
    if (deps.includes('otk')) preset['otk.view'] = true;
    if (deps.includes('sc')) preset['sc.view'] = true;
    return preset;
}

function getDepartmentByPermissionKey(permissionKey) {
    if (!permissionKey) return null;
    if (permissionKey.startsWith('warehouse.')) return 'warehouse';
    if (permissionKey.startsWith('recipes.')) return 'recipes';
    if (permissionKey.startsWith('orders.')) return 'orders';
    if (permissionKey.startsWith('production.')) return 'production';
    if (permissionKey.startsWith('shift_schedule.')) return 'shift-schedule';
    if (permissionKey.startsWith('otk.')) return 'otk';
    if (permissionKey.startsWith('sc.')) return 'sc';
    if (permissionKey.startsWith('users.')) return 'users';
    if (permissionKey.startsWith('tasks.')) return 'tasks';
    if (permissionKey.startsWith('archive.')) return 'archive';
    return null;
}

function syncPermissionsWithDepartments(permissionContainerSelector, selectedDepartments = []) {
    const container = document.querySelector(permissionContainerSelector);
    if (!container) return;
    const selected = new Set(Array.isArray(selectedDepartments) ? selectedDepartments : []);

    container.querySelectorAll('input[name="permissions"]').forEach((input) => {
        if (!(input instanceof HTMLInputElement)) return;
        const dep = getDepartmentByPermissionKey(input.value);
        if (!dep) {
            input.disabled = false;
            return;
        }
        const allowed = selected.has(dep);
        input.disabled = !allowed;
        if (!allowed) {
            input.checked = false;
        }
    });
}

function applyPermissionPresetToForm(role, departments = [], containerSelector = '#user-permissions-group') {
    const container = document.querySelector(containerSelector);
    if (!container) return;
    const preset = getDefaultPermissionPresetForRole(role, departments);
    container.querySelectorAll('input[name="permissions"]').forEach((input) => {
        if (input instanceof HTMLInputElement) {
            input.checked = Boolean(preset[input.value]);
        }
    });
}

window.applyPermissionQuickPreset = function(triggerEl, mode, encodedKeys = '') {
    const container = triggerEl ? triggerEl.closest('.form-group') : null;
    if (!container) return;
    const checkboxes = container.querySelectorAll('input[name="permissions"]');
    if (!checkboxes.length) return;

    if (mode === 'all') {
        checkboxes.forEach((input) => {
            if (input instanceof HTMLInputElement) input.checked = true;
        });
        return;
    }

    if (mode === 'none') {
        checkboxes.forEach((input) => {
            if (input instanceof HTMLInputElement) input.checked = false;
        });
        return;
    }

    if (mode === 'view') {
        let allowed = [];
        try {
            allowed = JSON.parse(decodeURIComponent(encodedKeys || '[]'));
        } catch (error) {
            allowed = [];
        }
        const allowedSet = new Set(Array.isArray(allowed) ? allowed : []);
        checkboxes.forEach((input) => {
            if (input instanceof HTMLInputElement) {
                input.checked = allowedSet.has(input.value);
            }
        });
    }
};

function getShiftChecklistDoneKey() {
    const userId = currentUser && currentUser.id ? currentUser.id : 'anonymous';
    return `${SHIFT_CHECKLIST_DONE_STORAGE_PREFIX}:${userId}`;
}

function getShiftRegulationDoneKey() {
    const userId = currentUser && currentUser.id ? currentUser.id : 'anonymous';
    return `${SHIFT_REGULATION_DONE_STORAGE_PREFIX}:${userId}`;
}

function getShiftEndChecklistDoneKey() {
    const userId = currentUser && currentUser.id ? currentUser.id : 'anonymous';
    return `${SHIFT_END_CHECKLIST_DONE_STORAGE_PREFIX}:${userId}`;
}

function getTodayDateKey() {
    const now = new Date();
    const y = now.getFullYear();
    const m = String(now.getMonth() + 1).padStart(2, '0');
    const d = String(now.getDate()).padStart(2, '0');
    return `${y}-${m}-${d}`;
}

function resetShiftStartDailyStatus() {
    shiftStartDailyStatus = {
        loaded: false,
        dateKey: null,
        checklistCompleted: false,
        regulationConfirmed: false,
        regulationOperatorNumber: null
    };
}

function shouldEnforceShiftChecklist() {
    return Boolean(currentUser)
        && !isOtkMode()
        && !isScMode()
        && userHasPermission('production.view');
}

function isChecklistRequiredButNotDone() {
    return shouldEnforceShiftChecklist() && !isShiftChecklistCompletedForToday();
}

async function refreshShiftStartDailyStatus(force = false) {
    if (!shouldEnforceShiftChecklist()) {
        shiftStartDailyStatus = {
            loaded: true,
            dateKey: getTodayDateKey(),
            checklistCompleted: true,
            regulationConfirmed: true,
            regulationOperatorNumber: null
        };
        return shiftStartDailyStatus;
    }

    const todayKey = getTodayDateKey();
    if (!force && shiftStartDailyStatus.loaded && shiftStartDailyStatus.dateKey === todayKey) {
        return shiftStartDailyStatus;
    }

    const fallback = {
        loaded: true,
        dateKey: todayKey,
        checklistCompleted: localStorage.getItem(getShiftChecklistDoneKey()) === todayKey,
        regulationConfirmed: localStorage.getItem(getShiftRegulationDoneKey()) === todayKey,
        regulationOperatorNumber: null
    };

    if (typeof api === 'undefined' || typeof api.getShiftStartDailyStatus !== 'function') {
        shiftStartDailyStatus = fallback;
        return shiftStartDailyStatus;
    }

    try {
        const data = await api.getShiftStartDailyStatus();
        shiftStartDailyStatus = {
            loaded: true,
            dateKey: data?.work_date ? String(data.work_date) : todayKey,
            checklistCompleted: Boolean(data?.checklist_completed),
            regulationConfirmed: Boolean(data?.regulation_confirmed),
            regulationOperatorNumber: data?.regulation?.operator_number
                ? String(data.regulation.operator_number)
                : null
        };
    } catch (error) {
        console.error('Ошибка загрузки статуса подтверждения смены:', error);
        shiftStartDailyStatus = fallback;
    }

    return shiftStartDailyStatus;
}

function normalizeChecklistItem(raw, index) {
    if (!raw) return null;
    if (typeof raw === 'string') {
        const text = raw.trim();
        if (!text) return null;
        return { id: `fallback-${Date.now()}-${index}`, text };
    }
    if (typeof raw === 'object') {
        const text = String(raw.text || '').trim();
        if (!text) return null;
        const id = String(raw.id || `fallback-${Date.now()}-${index}`).trim();
        return { id, text };
    }
    return null;
}

async function getShiftChecklistItems() {
    if (typeof api === 'undefined' || typeof api.getShiftChecklistItems !== 'function') {
        return SHIFT_CHECKLIST_DEFAULT_ITEMS.map(item => ({ ...item }));
    }

    try {
        const fromApi = await api.getShiftChecklistItems();
        const normalized = (Array.isArray(fromApi) ? fromApi : [])
            .map((item, index) => normalizeChecklistItem(item, index))
            .filter(Boolean);

        if (!normalized.length) {
            return SHIFT_CHECKLIST_DEFAULT_ITEMS.map(item => ({ ...item }));
        }
        return normalized;
    } catch (error) {
        console.error('Ошибка загрузки общего чеклиста смены:', error);
        return SHIFT_CHECKLIST_DEFAULT_ITEMS.map(item => ({ ...item }));
    }
}

function isShiftChecklistCompletedForToday() {
    return Boolean(shiftStartDailyStatus.checklistCompleted);
}

function isShiftRegulationConfirmedForToday() {
    return Boolean(shiftStartDailyStatus.regulationConfirmed);
}

function markShiftChecklistCompletedForToday() {
    shiftStartDailyStatus.loaded = true;
    shiftStartDailyStatus.dateKey = getTodayDateKey();
    shiftStartDailyStatus.checklistCompleted = true;
    localStorage.setItem(getShiftChecklistDoneKey(), getTodayDateKey());
}

function markShiftRegulationConfirmedForToday(operatorNumber = null) {
    shiftStartDailyStatus.loaded = true;
    shiftStartDailyStatus.dateKey = getTodayDateKey();
    shiftStartDailyStatus.regulationConfirmed = true;
    shiftStartDailyStatus.regulationOperatorNumber = operatorNumber ? String(operatorNumber) : null;
    localStorage.setItem(getShiftRegulationDoneKey(), getTodayDateKey());
}

function isShiftEndChecklistCompletedForToday() {
    return localStorage.getItem(getShiftEndChecklistDoneKey()) === getTodayDateKey();
}

function markShiftEndChecklistCompletedForToday() {
    localStorage.setItem(getShiftEndChecklistDoneKey(), getTodayDateKey());
}

function removeShiftChecklistModal(resetPromise = true) {
    const existing = document.getElementById('shift-checklist-overlay');
    if (existing) {
        existing.remove();
    }
    shiftChecklistModalOpen = false;
    if (resetPromise) {
        shiftChecklistModalPromise = null;
    }
}

function isShiftStartConfirmationPending() {
    if (!shiftStartDailyStatus.loaded) return true;
    // Единое правило на сутки: если чеклист уже подтвержден сегодня,
    // повторное подтверждение никому не требуется.
    return shouldEnforceShiftChecklist() && !isShiftChecklistCompletedForToday();
}

function createChecklistItemHtml(item, index, isChecked = false, canEdit = false) {
    return `
        <label class="shift-checklist-item" for="shift-checklist-item-${index}">
            <input type="checkbox" id="shift-checklist-item-${index}" data-item-id="${item.id}" ${isChecked ? 'checked' : ''}>
            <span class="shift-checklist-item-text">${item.text}</span>
            ${canEdit ? `<button type="button" class="shift-checklist-remove-btn" data-remove-id="${item.id}" title="Удалить пункт">×</button>` : ''}
        </label>
    `;
}

function renderShiftChecklistItems(container, items, checkedIds = new Set(), canEdit = false) {
    container.innerHTML = items
        .map((item, index) => createChecklistItemHtml(item, index, checkedIds.has(item.id), canEdit))
        .join('');
}

async function showShiftChecklistModal() {
    if (shiftChecklistModalOpen && shiftChecklistModalPromise) return shiftChecklistModalPromise;

    shiftChecklistModalOpen = true;
    const canEditChecklist = userHasPermission('checklist.manage');
    let checklistItems = await getShiftChecklistItems();

    shiftChecklistModalPromise = new Promise((resolve) => {
        removeShiftChecklistModal(false);

        const overlay = document.createElement('div');
        overlay.id = 'shift-checklist-overlay';
        overlay.className = 'shift-checklist-overlay';
        overlay.innerHTML = `
            <div class="shift-checklist-modal" role="dialog" aria-modal="true" aria-labelledby="shift-checklist-title">
                <h3 id="shift-checklist-title">Проверка перед началом смены</h3>
                <p class="shift-checklist-subtitle">
                    Отметьте все пункты. Только после этого откроется основной экран с заказами.
                </p>
                ${!canEditChecklist ? `
                    <div class="shift-checklist-role-note">
                        Редактирование списка пунктов доступно только администратору или менеджеру.
                    </div>
                ` : ''}
                <div id="shift-checklist-items" class="shift-checklist-items"></div>
                ${canEditChecklist ? `<div class="shift-checklist-add-row">
                    <input
                        type="text"
                        id="shift-checklist-new-item"
                        placeholder="Добавить пункт вручную..."
                        maxlength="180"
                    >
                    <button type="button" class="btn btn-secondary" id="shift-checklist-add-btn">Добавить</button>
                </div>
                <div class="shift-checklist-preset-row">
                    <button type="button" class="btn btn-secondary" id="shift-checklist-preset-btn">Загрузить рекомендованный SMD-чеклист</button>
                </div>` : ''}
                <div id="shift-checklist-hint" class="shift-checklist-hint" style="display: none;"></div>
                <div class="shift-checklist-comment-wrap">
                    <label for="shift-checklist-comment">Комментарий по утренней проверке (замечания, отклонения, что исправлено)</label>
                    <textarea id="shift-checklist-comment" rows="3" placeholder="Например: заменили фидер №4, повторно проверили давление воздуха."></textarea>
                </div>
                <div class="shift-checklist-actions">
                    <button type="button" class="btn btn-primary" id="shift-checklist-confirm-btn" disabled>
                        Подтвердить проверку
                    </button>
                </div>
            </div>
        `;

        document.body.appendChild(overlay);

        const checkedIds = new Set();

        const itemsContainer = overlay.querySelector('#shift-checklist-items');
        const addInput = overlay.querySelector('#shift-checklist-new-item');
        const addBtn = overlay.querySelector('#shift-checklist-add-btn');
        const presetBtn = overlay.querySelector('#shift-checklist-preset-btn');
        const confirmBtn = overlay.querySelector('#shift-checklist-confirm-btn');
        const hint = overlay.querySelector('#shift-checklist-hint');
        const commentInput = overlay.querySelector('#shift-checklist-comment');

        const refreshConfirmButton = () => {
            const hasItems = checklistItems.length > 0;
            const allChecked = hasItems && checklistItems.every(item => checkedIds.has(item.id));
            confirmBtn.disabled = !allChecked;
            if (!hasItems) {
                hint.style.display = 'block';
                hint.textContent = canEditChecklist
                    ? 'Добавьте хотя бы один пункт проверки.'
                    : 'Список проверки пуст. Обратитесь к администратору или менеджеру.';
            } else if (!allChecked) {
                hint.style.display = 'block';
                hint.textContent = 'Необходимо отметить все пункты.';
            } else {
                hint.style.display = 'none';
                hint.textContent = '';
            }
        };

        const rerenderItems = () => {
            renderShiftChecklistItems(itemsContainer, checklistItems, checkedIds, canEditChecklist);
            refreshConfirmButton();
        };

        rerenderItems();

        itemsContainer.addEventListener('change', (event) => {
            const target = event.target;
            if (!(target instanceof HTMLInputElement) || target.type !== 'checkbox') return;
            const itemId = target.getAttribute('data-item-id');
            if (!itemId) return;
            if (target.checked) {
                checkedIds.add(itemId);
            } else {
                checkedIds.delete(itemId);
            }
            refreshConfirmButton();
        });

        if (canEditChecklist) {
            itemsContainer.addEventListener('click', async (event) => {
            const target = event.target;
            if (!(target instanceof HTMLElement)) return;
            const removeId = target.getAttribute('data-remove-id');
            if (!removeId) return;

            event.preventDefault();
            event.stopPropagation();

            target.setAttribute('disabled', 'disabled');
            try {
                if (typeof api !== 'undefined' && typeof api.deleteShiftChecklistItem === 'function') {
                    await api.deleteShiftChecklistItem(removeId);
                }
            } catch (error) {
                console.error('Ошибка удаления пункта чеклиста:', error);
                showError(error.message || 'Не удалось удалить пункт');
                target.removeAttribute('disabled');
                return;
            }

            checklistItems = checklistItems.filter(item => item.id !== removeId);
            checkedIds.delete(removeId);
            rerenderItems();
            });
        }

        const addChecklistItem = async () => {
            const text = String(addInput.value || '').trim();
            if (!text) return;

            addBtn.disabled = true;
            try {
                let created = null;
                if (typeof api !== 'undefined' && typeof api.createShiftChecklistItem === 'function') {
                    created = await api.createShiftChecklistItem(text);
                }
                const normalizedCreated = normalizeChecklistItem(created || { id: `fallback-${Date.now()}`, text }, checklistItems.length);
                if (normalizedCreated) {
                    checklistItems.push(normalizedCreated);
                }
            } catch (error) {
                console.error('Ошибка добавления пункта чеклиста:', error);
                showError(error.message || 'Не удалось добавить пункт');
                addBtn.disabled = false;
                return;
            }

            addInput.value = '';
            rerenderItems();
            addInput.focus();
            addBtn.disabled = false;
        };

        if (canEditChecklist && addBtn && addInput) {
            addBtn.addEventListener('click', addChecklistItem);
            addInput.addEventListener('keydown', (event) => {
                if (event.key === 'Enter') {
                    event.preventDefault();
                    addChecklistItem();
                }
            });
        }

        if (canEditChecklist && presetBtn) {
            presetBtn.addEventListener('click', async () => {
                presetBtn.disabled = true;
                try {
                    if (typeof api === 'undefined' || typeof api.applySmdStartChecklistPreset !== 'function') {
                        throw new Error('API пресетов чеклиста недоступен');
                    }
                    const result = await api.applySmdStartChecklistPreset();
                    checklistItems = await getShiftChecklistItems();
                    rerenderItems();
                    showSuccess(
                        result && typeof result.created_count === 'number'
                            ? `Добавлено пунктов: ${result.created_count}`
                            : 'Рекомендованный SMD-чеклист загружен'
                    );
                } catch (error) {
                    console.error('Ошибка загрузки SMD-пресета чеклиста:', error);
                    showError(error.message || 'Не удалось загрузить рекомендованный чеклист');
                } finally {
                    presetBtn.disabled = false;
                }
            });
        }

        confirmBtn.addEventListener('click', async () => {
            confirmBtn.disabled = true;
            try {
                const comment = commentInput ? String(commentInput.value || '').trim() : '';
                const checklistTexts = checklistItems.map(item => item.text).filter(Boolean);
                if (typeof api !== 'undefined' && typeof api.completeShiftChecklist === 'function') {
                    await api.completeShiftChecklist(comment, checklistTexts);
                }
                markShiftChecklistCompletedForToday();
                removeShiftChecklistModal();
                shiftChecklistModalPromise = null;
                resolve(true);
            } catch (error) {
                console.error('Ошибка сохранения подтверждения чеклиста:', error);
                showError(error.message || 'Не удалось сохранить подтверждение чеклиста');
                refreshConfirmButton();
            }
        });
    });

    return shiftChecklistModalPromise;
}

async function ensureShiftChecklistBeforeMainScreen() {
    if (!isChecklistRequiredButNotDone()) return;
    await showShiftChecklistModal();
}

function showSmdOperatorRegulationForConfirmation() {
    if (!shouldEnforceShiftChecklist() || isShiftRegulationConfirmedForToday()) {
        return Promise.resolve(true);
    }

    const modalId = `smd-reg-confirm-${Date.now()}`;
    return new Promise((resolve) => {
        const regulationHtml = `
            <div class="smd-regulation">
                <h3>Регламент работы оператора SMD-линии</h3>
                <p>Подтвердите ознакомление с регламентом на текущую смену.</p>
                <h4>Ключевые правила</h4>
                <ul>
                    <li>Перед запуском: проверка оборудования, проекта, компонентов и материалов.</li>
                    <li>Первая плата и почасовой контроль обязательно проходят AOI.</li>
                    <li>При повторяемом браке линия останавливается, сообщается старшему смены.</li>
                    <li>По завершении: передача партии, заполнение CRM и уборка рабочего места.</li>
                </ul>
                <label class="shift-end-checklist-item" for="${modalId}-agree" style="margin-top: 6px;">
                    <input type="checkbox" id="${modalId}-agree">
                    <span>С регламентом ознакомлен(а), подтверждаю выполнение требований в текущей смене</span>
                </label>
                <div class="shift-checklist-comment-wrap" style="margin-top: 10px;">
                    <label for="${modalId}-operator-number">Номер оператора, прошедшего чеклист (вручную)</label>
                    <input type="text" id="${modalId}-operator-number" maxlength="64" placeholder="Например: 1024" style="width: 100%; padding: 10px 12px; border: 1px solid var(--tg-border); border-radius: 8px; background: var(--tg-bg); color: var(--tg-text);">
                </div>
                <div class="shift-end-checklist-actions">
                    <button class="btn btn-primary" id="${modalId}-confirm" disabled>Подтвердить регламент</button>
                </div>
            </div>
        `;

        showModal('Подтверждение регламента SMD', regulationHtml);

        const agree = document.getElementById(`${modalId}-agree`);
        const confirmBtn = document.getElementById(`${modalId}-confirm`);
        const operatorNumberInput = document.getElementById(`${modalId}-operator-number`);
        if (!agree || !confirmBtn || !operatorNumberInput) {
            resolve(false);
            return;
        }

        const refreshConfirmBtnState = () => {
            const operatorNumber = String(operatorNumberInput.value || '').trim();
            confirmBtn.disabled = !agree.checked || !operatorNumber;
        };

        agree.addEventListener('change', refreshConfirmBtnState);
        operatorNumberInput.addEventListener('input', refreshConfirmBtnState);
        refreshConfirmBtnState();

        confirmBtn.addEventListener('click', async () => {
            const operatorNumber = String(operatorNumberInput.value || '').trim();
            if (!operatorNumber) {
                showError('Введите номер оператора');
                return;
            }

            confirmBtn.disabled = true;
            try {
                if (typeof api !== 'undefined' && typeof api.confirmShiftRegulation === 'function') {
                    await api.confirmShiftRegulation(operatorNumber);
                }
                markShiftRegulationConfirmedForToday(operatorNumber);
                closeModal();
                resolve(true);
            } catch (error) {
                console.error('Ошибка подтверждения регламента SMD:', error);
                showError(error.message || 'Не удалось подтвердить регламент');
                refreshConfirmBtnState();
            }
        });
    });
}

async function ensureShiftStartAutoConfirmationFlow(forceOpen = false) {
    if (!shouldEnforceShiftChecklist()) return;
    await refreshShiftStartDailyStatus(forceOpen);
    if (!isShiftStartConfirmationPending()) return;
    if (shiftStartConfirmationInProgress) return;

    if (!forceOpen) {
        // Не блокируем интерфейс автоматически — только показываем предупреждение на главной.
        if (currentSection === 'dashboard') {
            await loadDashboardOrders();
        }
        return;
    }

    shiftStartConfirmationInProgress = true;
    try {
        if (currentSection !== 'dashboard') {
            showSection('dashboard');
        }

        if (!isShiftRegulationConfirmedForToday()) {
            await showSmdOperatorRegulationForConfirmation();
        }

        if (!isShiftChecklistCompletedForToday()) {
            await showShiftChecklistModal();
        }

        if (currentSection === 'dashboard') {
            await loadDashboardOrders();
        }
    } catch (error) {
        console.error('Ошибка автоматического подтверждения смены:', error);
    } finally {
        shiftStartConfirmationInProgress = false;
    }
}

async function ensureChecklistBeforeProductionStart() {
    await refreshShiftStartDailyStatus();
    if (!isShiftStartConfirmationPending()) return true;
    showError('Перед запуском производства нужно пройти чеклист смены.');
    await ensureShiftStartAutoConfirmationFlow(true);
    return !isShiftStartConfirmationPending();
}

