window.showShiftEndChecklist = function() {
    const modalId = `shift-end-checklist-${Date.now()}`;
    const alreadyDone = isShiftEndChecklistCompletedForToday();

    const itemsHtml = SHIFT_END_CHECKLIST_ITEMS.map((item, index) => `
        <label class="shift-end-checklist-item" for="${modalId}-item-${index}">
            <input type="checkbox" id="${modalId}-item-${index}" class="shift-end-checklist-checkbox">
            <span>${escapeHtml(item)}</span>
        </label>
    `).join('');

    const doneBadge = alreadyDone
        ? `<div class="shift-end-checklist-done">Сегодня чеклист завершения смены уже подтвержден</div>`
        : '';

    showModal('Чеклист завершения смены (SMD)', `
        ${doneBadge}
        <div class="shift-end-checklist-wrap" id="${modalId}">
            ${itemsHtml}
            <div class="shift-end-checklist-actions">
                <button class="btn btn-primary" id="${modalId}-confirm" disabled>Подтвердить завершение смены</button>
            </div>
        </div>
    `);

    const wrap = document.getElementById(modalId);
    if (!wrap) return;
    const checkboxes = Array.from(wrap.querySelectorAll('.shift-end-checklist-checkbox'));
    const confirmBtn = document.getElementById(`${modalId}-confirm`);
    if (!confirmBtn) return;

    const refreshBtn = () => {
        confirmBtn.disabled = !checkboxes.every(ch => ch.checked);
    };

    checkboxes.forEach(ch => ch.addEventListener('change', refreshBtn));
    refreshBtn();

    confirmBtn.addEventListener('click', () => {
        markShiftEndChecklistCompletedForToday();
        showSuccess('Чеклист завершения смены подтвержден');
        closeModal();
    });
};

