function stopShiftChecklistMonitoring() {
    if (shiftChecklistTimer) {
        clearTimeout(shiftChecklistTimer);
        shiftChecklistTimer = null;
    }
}

function startShiftChecklistMonitoring() {
    stopShiftChecklistMonitoring();
    if (!shouldEnforceShiftChecklist()) return;

    const now = new Date();
    const nextMidnight = new Date(now);
    nextMidnight.setHours(24, 0, 0, 0);
    const delay = Math.max(1000, nextMidnight.getTime() - now.getTime() + 200);

    shiftChecklistTimer = setTimeout(async () => {
        await ensureShiftStartAutoConfirmationFlow(false);
        startShiftChecklistMonitoring();
    }, delay);
}

// Функция переключения вкладок на странице входа - должна быть доступна сразу
// Регистрация отключена - только вход
window.showLoginTab = function(tabName) {
    // Игнорируем запросы на регистрацию
    if (tabName === 'register') return;
    
    const loginForm = document.getElementById('login-form');
        if (loginForm) loginForm.style.display = 'block';
};

// Простая функция переключения мобильного меню
function toggleMobileMenu() {
    const sidebar = document.querySelector('.sidebar');
    const overlay = document.getElementById('mobile-menu-overlay');
    const menuBtn = document.getElementById('mobile-menu-btn');
    const body = document.body;
    
    if (!sidebar) {
        console.error('Сайдбар не найден');
        return;
    }
    
    const isOpen = sidebar.classList.contains('mobile-open');
    
    if (isOpen) {
        // Закрываем меню
        sidebar.classList.remove('mobile-open');
        if (overlay) overlay.classList.remove('show');
        if (menuBtn) menuBtn.classList.remove('active');
        if (body) body.style.overflow = '';
    } else {
        // Открываем меню
        sidebar.classList.add('mobile-open');
        if (overlay) overlay.classList.add('show');
        if (menuBtn) menuBtn.classList.add('active');
        if (body) body.style.overflow = 'hidden';
    }
}

// Делаем функцию доступной глобально
window.toggleMobileMenu = toggleMobileMenu;

// Режим ОТК: true если путь /otk или /otk/
function isOtkMode() {
    const path = (window.location.pathname || '').replace(/\/+$/, '');
    return path === '/otk' || path.startsWith('/otk/');
}

// Режим СЦ: true если путь /sc или /sc/
function isScMode() {
    const path = (window.location.pathname || '').replace(/\/+$/, '');
    return path === '/sc' || path.startsWith('/sc/');
}

// Переключение между производством, ОТК и СЦ
window.goToOtk = function() { window.location.href = '/otk'; };
window.goToSc = function() { window.location.href = '/sc'; };
window.goToProduction = function() { window.location.href = '/'; };

// Удаление пустого query string из URL
function cleanEmptyQueryString() {
    const url = window.location.href;
    // Если URL заканчивается на "?" или содержит только "?", убираем его
    if (url.endsWith('?')) {
        const cleanUrl = url.slice(0, -1);
        window.history.replaceState({}, document.title, cleanUrl);
    } else if (url.includes('?')) {
        const [path, query] = url.split('?');
        // Если query string пустой или содержит только пробелы, убираем его
        if (!query || query.trim() === '') {
            window.history.replaceState({}, document.title, path);
        }
    }
}

// Замена <use> на inline SVG для hover-анимаций отдельных частей иконок
function inlineSidebarIcons() {
    const selectors = '.sidebar .nav-icon svg use, .mobile-nav-bar svg use';
    document.querySelectorAll(selectors).forEach(useEl => {
        const href = useEl.getAttribute('href');
        if (!href) return;
        const symbolId = href.replace('#', '');
        const symbol = document.getElementById(symbolId);
        if (!symbol) return;

        const svg = useEl.closest('svg');
        const vb = symbol.getAttribute('viewBox');
        if (vb) svg.setAttribute('viewBox', vb);
        svg.dataset.icon = symbolId;

        ['fill', 'stroke', 'stroke-width', 'stroke-linecap', 'stroke-linejoin'].forEach(attr => {
            const val = symbol.getAttribute(attr);
            if (val) svg.setAttribute(attr, val);
        });

        useEl.remove();
        Array.from(symbol.children).forEach(child => svg.appendChild(child.cloneNode(true)));
    });
}

// Инициализация при загрузке страницы
document.addEventListener('DOMContentLoaded', async () => {
    try {
        // Очистка пустого query string из URL
        cleanEmptyQueryString();
        
        // Инициализация темы (должна быть первой, чтобы избежать мерцания)
        initTheme();
        
        // Инлайн SVG-иконок для hover-анимаций
        inlineSidebarIcons();
        
        // Настройка формы входа - должна быть доступна всегда
        setupLoginForm();
        
        // Инициализация мобильного меню
        initMobileMenu();
        
        // Ждём загрузки api
        if (typeof api === 'undefined') {
            console.error('API не загружен! Проверьте, что api.js загружается перед app.js');
            showLoginScreen();
            return;
        }
        
        // Проверка авторизации
        await checkAuth();
    } catch (error) {
        console.error('Ошибка инициализации:', error);
        showLoginScreen();
    }
});

// Инициализация мобильного меню
function initMobileMenu() {
    // Инициализация горизонтального мобильного меню
    const mobileNavItems = document.querySelectorAll('.mobile-nav-item');
    
    // Фильтрация элементов меню по правам доступа
    function filterMobileNavByAccess() {
        if (!currentUser) return;
        
        mobileNavItems.forEach(item => {
            const section = item.getAttribute('data-section');
            const role = item.getAttribute('data-role');
            
            // Скрываем элементы, требующие определенной роли
            if (role && currentUser.role !== role) {
                item.style.display = 'none';
            } else {
                item.style.display = 'flex';
            }
            
            if (!section) return;
            if (section === 'dashboard') return;

            const requiredPermission = SECTION_VIEW_PERMISSION_MAP[section];
            if (requiredPermission && !userHasPermission(requiredPermission)) {
                item.style.display = 'none';
            }
        });
    }
    
    // Применяем фильтрацию при инициализации
    filterMobileNavByAccess();
    
    // Применяем фильтрацию при изменении пользователя
    const userObserver = new MutationObserver(filterMobileNavByAccess);
    if (document.body) {
        userObserver.observe(document.body, { 
            childList: true, 
            subtree: true,
            attributes: true,
            attributeFilter: ['data-user']
        });
    }
    
    // Обработчики кликов
    mobileNavItems.forEach(item => {
        item.addEventListener('click', function(e) {
            e.preventDefault();
            e.stopPropagation();
            const section = this.getAttribute('data-section');
            if (section) {
                // Убираем активный класс со всех элементов
                mobileNavItems.forEach(nav => nav.classList.remove('active'));
                // Добавляем активный класс к текущему элементу
                this.classList.add('active');
                // Переключаем секцию
                if (window.showSection) {
                    window.showSection(section);
                }
            }
        });
    });
    
    // Обновление активного элемента при переключении секций
    const observer = new MutationObserver(function(mutations) {
        mutations.forEach(function(mutation) {
            if (mutation.type === 'attributes' && mutation.attributeName === 'class') {
                const activeSection = document.querySelector('.content-section.active');
                if (activeSection) {
                    const sectionId = activeSection.id;
                    mobileNavItems.forEach(item => {
                        if (item.style.display !== 'none') {
                            item.classList.remove('active');
                            if (item.getAttribute('data-section') === sectionId) {
                                item.classList.add('active');
                            }
                        }
                    });
                }
            }
        });
    });
    
    // Наблюдаем за изменениями в секциях контента
    const contentSections = document.querySelectorAll('.content-section');
    contentSections.forEach(section => {
        observer.observe(section, { attributes: true, attributeFilter: ['class'] });
    });
}

// Проверка авторизации
async function checkAuth() {
    if (typeof api === 'undefined') {
        showLoginScreen();
        return;
    }
    
    const token = api.getToken();
    
    if (!token) {
        showLoginScreen();
        return;
    }

    try {
        const result = await api.getCurrentUser();
        currentUser = result.user;
        resetShiftStartDailyStatus();
        showApp();
        startShiftChecklistMonitoring();
        // Проверка API
        checkApiConnection();
        // Фильтрация навигации по правам доступа
        filterNavigationByAccess();
        // Режим по пути: /otk — интерфейс ОТК, / — производство
        applyAppMode();
        // Обновляем видимость кнопки создания заказа
        updateCreateOrderButtonVisibility();
        // Фильтрация мобильного меню
        if (typeof initMobileMenu === 'function') {
            initMobileMenu();
        }
        // Навигация
        setupNavigation();
        // Загрузка начальных данных
        await loadInitialData();
        // Загрузка данных для стартовой секции
        if (isOtkMode()) {
            currentSection = 'otk-pending';
            await loadOtkPending();
        } else if (isScMode()) {
            currentSection = 'sc-pending';
            await loadScPending();
        } else {
            await loadDashboard();
            currentSection = 'dashboard';
            await ensureShiftStartAutoConfirmationFlow();
        }
        // Автообновление по умолчанию выключено, но обновляем UI кнопки
        updateAutoRefreshButton();
    } catch (error) {
        console.error('Ошибка проверки авторизации:', error);
        showLoginScreen();
    }
}

// Показать экран входа
function showLoginScreen() {
    const loginScreen = document.getElementById('login-screen');
    const appContainer = document.getElementById('app-container');
    
    if (loginScreen) {
        loginScreen.style.display = 'flex';
    }
    if (appContainer) {
        appContainer.style.display = 'none';
    }
}

// Показать приложение
function showApp() {
    const loginScreen = document.getElementById('login-screen');
    const appContainer = document.getElementById('app-container');
    
    if (loginScreen) {
        loginScreen.style.display = 'none';
    }
    if (appContainer) {
        appContainer.style.display = 'flex';
    }
    
    // Показать информацию о пользователе
    if (currentUser) {
        const userInfo = document.getElementById('userInfo');
        const userName = document.getElementById('userName');
        if (userInfo && userName) {
            userName.textContent = currentUser.full_name || currentUser.username;
            userInfo.style.display = 'flex';
        }
    }
    
    // Проверка API с автоматическим мониторингом
    startConnectionMonitoring();
    startClientVersionMonitoring();
}

// Настройка формы входа
// Функция showLoginTab уже определена в начале файла

window.setupLoginForm = function() {
    // Настройка обработчиков для кнопок вкладок
    const loginTabButtons = document.querySelectorAll('.login-tab-btn');
    loginTabButtons.forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            const tabName = this.getAttribute('data-tab');
            if (tabName && window.showLoginTab) {
                window.showLoginTab(tabName);
            }
        });
    });
    
    const loginForm = document.getElementById('login-form');
    if (loginForm) {
        // Удаляем старый обработчик, если есть
        const newLoginForm = loginForm.cloneNode(true);
        loginForm.parentNode.replaceChild(newLoginForm, loginForm);
        
        const form = document.getElementById('login-form');
        form.addEventListener('submit', async (e) => {
            e.preventDefault();
            e.stopPropagation();
            
            const usernameInput = document.getElementById('login-username');
            const passwordInput = document.getElementById('login-password');
            const errorDiv = document.getElementById('login-error');
            const submitBtn = form.querySelector('button[type="submit"]');
            
            if (!usernameInput || !passwordInput) {
                console.error('Поля формы не найдены');
                return;
            }
            
            const username = usernameInput.value.trim();
            const password = passwordInput.value;
            
            if (!username || !password) {
                errorDiv.textContent = 'Заполните все поля';
                errorDiv.style.display = 'block';
                return;
            }
            
            errorDiv.style.display = 'none';
            errorDiv.textContent = '';
            
            // Блокируем кнопку во время отправки
            if (submitBtn) {
                submitBtn.disabled = true;
                submitBtn.textContent = 'Вход...';
            }
            
            try {
                if (typeof api === 'undefined') {
                    throw new Error('API не загружен');
                }
                const loginWithTimeout = Promise.race([
                    api.login(username, password),
                    new Promise((_, reject) => 
                        setTimeout(() => reject(new Error('Сервер не отвечает. Проверьте подключение.')), 15000)
                    )
                ]);
                const result = await loginWithTimeout;
                if (result.success) {
                    currentUser = result.user;
                    resetShiftStartDailyStatus();
                    showApp();
                    startShiftChecklistMonitoring();
                    checkApiConnection();
                    filterNavigationByAccess();
                    applyAppMode();
                    updateCreateOrderButtonVisibility();
                    if (typeof initMobileMenu === 'function') initMobileMenu();
                    setupNavigation();
                    currentSection = 'dashboard';
                    loadInitialData().catch(e => console.error('loadInitialData:', e));
                    await loadDashboard();
                    await ensureShiftStartAutoConfirmationFlow();
                } else {
                    throw new Error(result.message || 'Ошибка входа');
                }
            } catch (error) {
                console.error('Ошибка входа:', error);
                errorDiv.textContent = error.message || 'Ошибка входа. Проверьте логин и пароль.';
                errorDiv.style.display = 'block';
            } finally {
                // Разблокируем кнопку
                if (submitBtn) {
                    submitBtn.disabled = false;
                    submitBtn.textContent = 'Войти';
                }
            }
        });
        
        // Также добавляем обработчик на кнопку для мобильных устройств
        const submitButton = form.querySelector('button[type="submit"]');
        if (submitButton) {
            submitButton.addEventListener('click', (e) => {
                // Предотвращаем двойную отправку
                e.preventDefault();
                form.dispatchEvent(new Event('submit'));
            });
        }
    }

    // Форма регистрации
    // Регистрация отключена
    const registerForm = document.getElementById('register-form');
    if (false && registerForm) {
        registerForm.addEventListener('submit', async (e) => {
            e.preventDefault();
            const errorDiv = document.getElementById('register-error');
            const successDiv = document.getElementById('register-success');
            
            errorDiv.style.display = 'none';
            successDiv.style.display = 'none';
            errorDiv.textContent = '';
            successDiv.textContent = '';
            
            const username = document.getElementById('register-username').value.trim();
            const password = document.getElementById('register-password').value;
            const fullName = document.getElementById('register-full-name').value.trim();
            const email = document.getElementById('register-email').value.trim();
            const birthDate = document.getElementById('register-birth-date').value;
            const phone = document.getElementById('register-phone').value.trim();
            
            // Валидация обязательных полей
            if (!birthDate) {
                errorDiv.textContent = 'Дата рождения обязательна для заполнения';
                errorDiv.style.display = 'block';
                return;
            }
            
            if (!phone) {
                errorDiv.textContent = 'Номер телефона обязателен для заполнения';
                errorDiv.style.display = 'block';
                return;
            }
            
            try {
                if (typeof api === 'undefined') {
                    throw new Error('API не загружен');
                }
                
                const result = await api.register({
                    username,
                    password,
                    full_name: fullName,
                    email,
                    birth_date: birthDate,
                    phone
                });
                
                if (result.success) {
                    successDiv.textContent = result.message || 'Регистрация успешна! Ожидайте подтверждения администратора.';
                    successDiv.style.display = 'block';
                    registerForm.reset();
                    // Переключаем на вкладку входа через 3 секунды
                    setTimeout(() => {
                        showLoginTab('login');
                    }, 3000);
                }
            } catch (error) {
                errorDiv.textContent = error.message || 'Ошибка регистрации';
                errorDiv.style.display = 'block';
            }
        });
    }

};

// Показать форму сброса пароля по токену
// Функция для администратора: сброс пароля пользователя
window.resetUserPassword = async function(userId, username) {
    
    const newPassword = await showPromptModal(
        `Введите новый пароль для пользователя "${username}" (минимум 6 символов):`,
        'Смена пароля',
        { placeholder: 'Новый пароль', required: true, min: 6 }
    );
    
    if (!newPassword) {
        return; // Пользователь отменил
    }
    
    if (newPassword.length < 6) {
        showError('Пароль должен содержать минимум 6 символов');
        return;
    }
    
    const confirmPassword = await showPromptModal(
        'Подтвердите новый пароль:',
        'Подтверждение пароля',
        { placeholder: 'Повторите пароль', required: true }
    );
    
    if (!confirmPassword) {
        return;
    }
    
    if (newPassword !== confirmPassword) {
        showError('Пароли не совпадают');
        return;
    }
    
    try {
        
        // Используем API для сброса пароля администратором
        const result = await api.request('/api/auth/admin/reset-password', {
            method: 'POST',
            body: JSON.stringify({
                user_id: userId,
                new_password: newPassword
            })
        });
        
        
        if (result && result.success) {
            showSuccess(result.message || `Пароль для пользователя "${username}" успешно изменен`);
            // Обновляем список пользователей, если он отображается
            const usersSection = document.getElementById('users');
            if (usersSection && usersSection.classList.contains('active')) {
                loadUsers();
            }
        } else {
            const errorMsg = result?.error || 'Ошибка сброса пароля';
            console.error('❌ Ошибка в ответе:', errorMsg);
            showError(errorMsg);
        }
    } catch (error) {
        console.error('❌ Ошибка сброса пароля:', error);
        console.error('   Детали ошибки:', {
            message: error.message,
            stack: error.stack
        });
        showError('Ошибка сброса пароля: ' + (error.message || 'Неизвестная ошибка'));
    }
};

// Выход из системы (теперь просто перезагружает страницу)
async function logout() {
    const confirmed = await showConfirmModal('Вы уверены, что хотите выйти?', 'Выход');
    if (confirmed) {
        stopShiftChecklistMonitoring();
        stopClientVersionMonitoring();
        removeShiftChecklistModal();
        api.clearToken();
        currentUser = null;
        resetShiftStartDailyStatus();
        window.location.reload();
    }
}

// Сделать функцию доступной глобально
window.logout = logout;

// Управление темой
function initTheme() {
    const savedTheme = localStorage.getItem('theme') || 'light';
    setTheme(savedTheme);
}

function setTheme(theme) {
    document.documentElement.setAttribute('data-theme', theme);
    localStorage.setItem('theme', theme);
    
    const sunIcon = document.getElementById('theme-icon-sun');
    const moonIcon = document.getElementById('theme-icon-moon');
    
    if (theme === 'dark') {
        if (sunIcon) sunIcon.style.display = 'block';
        if (moonIcon) moonIcon.style.display = 'none';
    } else {
        if (sunIcon) sunIcon.style.display = 'none';
        if (moonIcon) moonIcon.style.display = 'block';
    }
}

function toggleTheme() {
    const currentTheme = document.documentElement.getAttribute('data-theme') || 'light';
    const newTheme = currentTheme === 'light' ? 'dark' : 'light';
    setTheme(newTheme);
}

// Инициализация темы при загрузке
window.toggleTheme = toggleTheme;

// Функция toggleMobileMenu уже определена в начале файла (строка 34)

// Swipe жесты для закрытия меню
let touchStartX = 0;
let touchStartY = 0;
let touchEndX = 0;
let touchEndY = 0;

window.addEventListener('touchstart', (e) => {
    touchStartX = e.changedTouches[0].screenX;
    touchStartY = e.changedTouches[0].screenY;
}, { passive: true });

window.addEventListener('touchend', (e) => {
    touchEndX = e.changedTouches[0].screenX;
    touchEndY = e.changedTouches[0].screenY;
    handleSwipe();
}, { passive: true });

function handleSwipe() {
    const sidebar = document.querySelector('.sidebar');
    if (!sidebar || !sidebar.classList.contains('mobile-open')) return;
    
    const deltaX = touchEndX - touchStartX;
    const deltaY = touchEndY - touchStartY;
    
    // Проверяем, что это горизонтальный свайп (не вертикальный)
    if (Math.abs(deltaX) > Math.abs(deltaY) && Math.abs(deltaX) > 50) {
        // Свайп влево - закрываем меню
        if (deltaX < 0) {
            window.toggleMobileMenu();
        }
    }
}

// Инициализация мобильного меню
document.addEventListener('DOMContentLoaded', () => {
    // Закрытие мобильного меню при клике на overlay
    const overlay = document.getElementById('mobile-menu-overlay');
    if (overlay) {
        overlay.addEventListener('click', () => {
            window.toggleMobileMenu();
        });
    }
    
    // Закрытие меню при клике на ссылку на мобильных
    document.addEventListener('click', (e) => {
        if (window.innerWidth <= 768) {
            const navLink = e.target.closest('.nav-link');
            if (navLink) {
                setTimeout(() => {
                    window.toggleMobileMenu();
                }, 100);
            }
        }
    });
});

// Проверка подключения к API
// Функция проверки подключения к API
async function checkApiConnection() {
    const statusEl = document.getElementById('apiStatus');
    if (!statusEl) {
        console.error('Элемент apiStatus не найден');
        return;
    }
    
    // Показываем статус проверки
    statusEl.innerHTML = '<span class="status-dot"></span>';
    statusEl.className = 'api-status';
    
    try {
        const startTime = Date.now();
        const data = await api.healthCheck();
        const responseTime = Date.now() - startTime;
        
        
        statusEl.innerHTML = `<span class="status-dot active"></span>`;
        statusEl.className = 'api-status connected';
        
        // Endpoint больше не отображается в интерфейсе
        
    } catch (error) {
        console.error('Ошибка проверки API:', error);
        const errorMessage = error.message || 'Неизвестная ошибка';
        statusEl.innerHTML = `<span class="status-dot"></span>`;
        statusEl.className = 'api-status disconnected';
        statusEl.title = errorMessage; // Показываем полное сообщение при наведении
    }
}

// Автоматическая проверка подключения каждые 30 секунд
let connectionCheckInterval = null;

function startConnectionMonitoring() {
    // Останавливаем предыдущий интервал, если есть
    if (connectionCheckInterval) {
        clearInterval(connectionCheckInterval);
    }
    
    // Проверяем сразу
    checkApiConnection();
    
    // Затем каждые 30 секунд
    connectionCheckInterval = setInterval(() => {
        checkApiConnection();
    }, 30000);
    
}

function stopConnectionMonitoring() {
    if (connectionCheckInterval) {
        clearInterval(connectionCheckInterval);
        connectionCheckInterval = null;
    }
}

function forceReloadWithCacheBust() {
    const url = new URL(window.location.href);
    url.searchParams.set('_v', Date.now().toString());
    window.location.replace(url.toString());
}

async function checkClientVersionUpdate() {
    if (!currentUser) return;
    if (!api || typeof api.getClientVersion !== 'function') return;

    try {
        const data = await api.getClientVersion();
        const serverVersion = data && data.version ? String(data.version).trim() : '';
        if (!serverVersion) return;

        if (!currentClientBuildVersion) {
            currentClientBuildVersion = serverVersion;
            return;
        }

        if (currentClientBuildVersion !== serverVersion) {
            pendingClientBuildVersion = serverVersion;
            if (dismissedClientBuildVersion !== serverVersion) {
                showClientUpdateBanner();
            }
        }
    } catch (error) {
        console.warn('Не удалось проверить версию клиента:', error.message || error);
    }
}

function hideClientUpdateBanner() {
    const existing = document.getElementById('client-update-banner');
    if (existing) {
        existing.remove();
    }
}

function showClientUpdateBanner() {
    if (!pendingClientBuildVersion) return;

    let banner = document.getElementById('client-update-banner');
    if (!banner) {
        banner = document.createElement('div');
        banner.id = 'client-update-banner';
        banner.style.cssText = 'position:fixed;left:16px;right:16px;bottom:16px;z-index:10050;background:var(--tg-bg,#fff);color:var(--tg-text,#111);border:1px solid var(--tg-border,#ddd);box-shadow:0 8px 24px rgba(0,0,0,.12);border-radius:10px;padding:12px 14px;display:flex;align-items:center;gap:10px;flex-wrap:wrap;';
        banner.innerHTML = `
            <div style="flex:1;min-width:220px;">
                Доступно обновление CRM. Сохраните изменения и нажмите «Обновить».
            </div>
            <button type="button" class="btn btn-primary btn-small" id="client-update-banner-refresh">Обновить</button>
            <button type="button" class="btn btn-secondary btn-small" id="client-update-banner-later">Позже</button>
        `;
        document.body.appendChild(banner);

        const refreshBtn = document.getElementById('client-update-banner-refresh');
        const laterBtn = document.getElementById('client-update-banner-later');
        if (refreshBtn) {
            refreshBtn.addEventListener('click', () => {
                forceReloadWithCacheBust();
            });
        }
        if (laterBtn) {
            laterBtn.addEventListener('click', () => {
                dismissedClientBuildVersion = pendingClientBuildVersion;
                hideClientUpdateBanner();
            });
        }
    }
}

function startClientVersionMonitoring() {
    stopClientVersionMonitoring();
    currentClientBuildVersion = null;
    pendingClientBuildVersion = null;
    dismissedClientBuildVersion = null;

    checkClientVersionUpdate();
    clientVersionCheckInterval = setInterval(() => {
        checkClientVersionUpdate();
    }, 60000);
}

function stopClientVersionMonitoring() {
    if (clientVersionCheckInterval) {
        clearInterval(clientVersionCheckInterval);
        clientVersionCheckInterval = null;
    }
    hideClientUpdateBanner();
}

// Настройка навигации
function setupNavigation() {
    const navLinks = document.querySelectorAll('.nav-link');
    
    if (navLinks.length === 0) {
        console.error('Навигационные ссылки не найдены');
        return;
    }
    
    navLinks.forEach((link, index) => {
        const section = link.dataset.section;
        const href = link.getAttribute('href');
        
        link.addEventListener('click', (e) => {
            // Ссылки на другой путь (/otk, /) — разрешаем переход
            if (href && href.startsWith('/') && href !== '#') {
                return; // не preventDefault — браузер перейдёт
            }
            
            e.preventDefault();
            
            if (!section) {
                console.error('Атрибут data-section не найден у ссылки', link);
                return;
            }
            
            showSection(section);
            
            navLinks.forEach(l => l.classList.remove('active'));
            link.classList.add('active');
        });
    });
    
    // Устанавливаем активную ссылку для dashboard по умолчанию
    const dashboardLink = document.querySelector('.nav-link[data-section="dashboard"]');
    if (dashboardLink) {
        dashboardLink.classList.add('active');
    } else {
    }
}

// Показать секцию
function showSection(sectionName) {
    
    if (!sectionName) {
        console.error('Название секции не указано');
        return;
    }

    // Скрываем все секции
    const allSections = document.querySelectorAll('.content-section');
    allSections.forEach(s => {
        s.classList.remove('active');
    });
    
    // Показываем нужную секцию
    const section = document.getElementById(sectionName);
    if (!section) {
        console.error(`Секция с id="${sectionName}" не найдена`);
        // Показываем список всех доступных секций для отладки
        const availableSections = Array.from(allSections).map(s => s.id).filter(id => id);
        return;
    }
    
    section.classList.add('active');
    
    // Проверяем, что класс добавлен
    if (!section.classList.contains('active')) {
        console.error('Не удалось добавить класс active к секции');
    }
    
    // Обновляем заголовок
    const titles = {
        dashboard: 'Главная панель',
        warehouse: 'Управление складом',
        recipes: 'Рецептура',
        orders: 'Заказы',
        planning: 'Планирование производства',
        production: 'Управление производством',
        archive: 'Архивы',
        'shift-schedule': 'График смен',
        users: 'Пользователи',
        'ready-to-ship': 'Готовая продукция',
        finished: 'Готовая продукция',
        operators: 'Управление операторами',
        'otk-pending': 'Партии на проверке ОТК',
        'otk-ready': 'Готово к отгрузке',
        'otk-regulations': 'Регламенты',
        'otk-reports': 'Отчёты ОТК',
        'sc-pending': 'Партии на исправление',
        'sc-completed': 'Завершённые ремонты'
    };
    
    const pageTitle = document.getElementById('page-title');
    if (pageTitle) {
        pageTitle.textContent = titles[sectionName] || 'CRM';
    } else {
    }
    
    // Обновляем текущую секцию для автообновления
    currentSection = sectionName;
    
    // Инициализация полей по умолчанию для определенных секций
    if (sectionName === 'shift-schedule') {
        // Календарь по умолчанию: текущий месяц с 1-го числа
        setTimeout(() => {
            const startDateInput = document.getElementById('schedule-start-date');
            const daysCountInput = document.getElementById('schedule-days-count');
            if (startDateInput) {
                const now = new Date();
                const firstDay = new Date(now.getFullYear(), now.getMonth(), 1);
                const firstDayStr = firstDay.toISOString().split('T')[0];
                const daysInMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).getDate();
                if (!startDateInput.value) {
                    startDateInput.value = firstDayStr;
                    if (daysCountInput) daysCountInput.value = daysInMonth;
                }
            }
        }, 100);
    }
    if (sectionName === 'otk-reports') {
        setTimeout(() => {
            const fromEl = document.getElementById('otk-report-date-from');
            const toEl = document.getElementById('otk-report-date-to');
            if (fromEl && !fromEl.value) {
                const now = new Date();
                fromEl.value = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
            }
            if (toEl && !toEl.value) {
                toEl.value = new Date().toISOString().split('T')[0];
            }
        }, 100);
    }
    
    // Загружаем данные для секции
    loadSectionData(sectionName);
    
    // Перезапускаем автообновление
    startAutoRefresh();
}

// Делаем функцию доступной глобально
window.showSection = showSection;

// =============== АВТООБНОВЛЕНИЕ ДАННЫХ ===============

// Запуск автообновления
function startAutoRefresh() {
    // Останавливаем предыдущий интервал, если есть
    stopAutoRefresh();
    
    if (!autoRefreshEnabled || !isTabActive) {
        return;
    }
    
    // Запускаем автообновление
    autoRefreshInterval = setInterval(() => {
        if (!autoRefreshEnabled || !isTabActive || !currentSection) {
            return;
        }
        
        // Обновляем данные текущей секции
        loadSectionData(currentSection).catch(error => {
            console.error('Ошибка автообновления:', error);
        });
    }, autoRefreshIntervalMs);
    
}

// Остановка автообновления
function stopAutoRefresh() {
    if (autoRefreshInterval) {
        clearInterval(autoRefreshInterval);
        autoRefreshInterval = null;
    }
}

// Включение/выключение автообновления
function toggleAutoRefresh() {
    autoRefreshEnabled = !autoRefreshEnabled;
    
    // Обновляем UI кнопки
    const icon = document.getElementById('auto-refresh-icon');
    
    if (autoRefreshEnabled) {
        startAutoRefresh();
        if (icon) {
            icon.style.stroke = 'var(--tg-success)';
            icon.style.opacity = '1';
        }
        showToast('Автообновление включено (30 сек)', 'success');
    } else {
        stopAutoRefresh();
        if (icon) {
            icon.style.stroke = 'var(--tg-text-secondary)';
            icon.style.opacity = '0.5';
        }
        showToast('Автообновление выключено', 'info');
    }
    return autoRefreshEnabled;
}

// Обновление UI кнопки автообновления при загрузке
function updateAutoRefreshButton() {
    const icon = document.getElementById('auto-refresh-icon');
    
    if (icon) {
        if (autoRefreshEnabled) {
            icon.style.stroke = 'var(--tg-success)';
            icon.style.opacity = '1';
        } else {
            icon.style.stroke = 'var(--tg-text-secondary)';
            icon.style.opacity = '0.5';
        }
    }
}

// Отслеживание активности вкладки
document.addEventListener('visibilitychange', () => {
    isTabActive = !document.hidden;
    
    if (isTabActive) {
        // Вкладка стала активной - запускаем автообновление
        if (autoRefreshEnabled && currentSection) {
            startAutoRefresh();
            // Сразу обновляем данные
            loadSectionData(currentSection).catch(error => {
                console.error('Ошибка обновления при активации вкладки:', error);
            });
        }
    } else {
        // Вкладка стала неактивной - останавливаем автообновление
        stopAutoRefresh();
    }
});

// Остановка автообновления при выгрузке страницы
window.addEventListener('beforeunload', () => {
    stopAutoRefresh();
    stopShiftChecklistMonitoring();
    stopClientVersionMonitoring();
});

// Загрузка данных для секции (с защитой от гонки при быстром переключении)
async function loadSectionData(sectionName) {
    const myLoadId = ++_sectionLoadId;
    try {
        switch(sectionName) {
            case 'dashboard':
                await loadDashboard();
                break;
            case 'warehouse':
                await loadWarehouse();
                break;
            case 'production-stock':
                await loadProductionStock();
                break;
            case 'recipes':
                await loadRecipes();
                break;
            case 'orders':
                await loadOrders();
                break;
            case 'production':
                await loadProduction();
                break;
            case 'archive':
                await loadArchive();
                break;
            case 'users':
                await loadUsers();
                break;
            case 'shift-schedule':
                await loadShiftSchedule();
                break;
            case 'otk-pending':
                await loadOtkPending();
                break;
            case 'otk-ready':
                await loadOtkReady();
                break;
            case 'otk-regulations':
                await loadOtkRegulations();
                break;
            case 'otk-reports':
                await loadOtkReports();
                break;
            case 'sc-pending':
                await loadScPending();
                break;
            case 'sc-completed':
                await loadScCompleted();
                break;
        }
    } catch (error) {
        if (myLoadId !== _sectionLoadId) return;
        console.error('Ошибка загрузки данных:', error);
        showError('Ошибка загрузки данных: ' + error.message);
    }
}

