// Делаем функцию доступной глобально
window.loadDashboardOrders = loadDashboardOrders;

// =============== ОБЩИЕ ЗАДАЧИ ===============

let _dashboardTab = 'orders';

function switchDashboardTab(tab) {
    _dashboardTab = tab;
    const ordersSection = document.getElementById('orders-showroom-section');
    const tasksSection = document.getElementById('tasks-section');
    const tabOrders = document.getElementById('dash-tab-orders');
    const tabTasks = document.getElementById('dash-tab-tasks');
    const refreshOrders = document.getElementById('dash-refresh-orders');
    const refreshTasks = document.getElementById('dash-refresh-tasks');

    if (tab === 'orders') {
        if (ordersSection) ordersSection.style.display = '';
        if (tasksSection) tasksSection.style.display = 'none';
        if (tabOrders) tabOrders.classList.add('active');
        if (tabTasks) tabTasks.classList.remove('active');
        if (refreshOrders) refreshOrders.style.display = '';
        if (refreshTasks) refreshTasks.style.display = 'none';
    } else {
        if (ordersSection) ordersSection.style.display = 'none';
        if (tasksSection) tasksSection.style.display = '';
        if (tabOrders) tabOrders.classList.remove('active');
        if (tabTasks) tabTasks.classList.add('active');
        if (refreshOrders) refreshOrders.style.display = 'none';
        if (refreshTasks) refreshTasks.style.display = '';
        loadDashboardTasks();
    }
}
window.switchDashboardTab = switchDashboardTab;

async function loadDashboardTasks() {
    const container = document.getElementById('tasks-container');
    if (!container) return;
    try {
        const isManager = userHasPermission('tasks.manage');
        const addForm = document.getElementById('tasks-add-form');
        if (addForm) addForm.style.display = isManager ? '' : 'none';

        const tasks = await api.getTasks();
        const pending = tasks.filter(t => t.status === 'pending');
        const completed = tasks.filter(t => t.status === 'completed');

        const badge = document.getElementById('tasks-pending-badge');
        if (badge) {
            if (pending.length > 0) {
                badge.textContent = pending.length;
                badge.style.display = '';
            } else {
                badge.style.display = 'none';
            }
        }

        if (tasks.length === 0) {
            container.innerHTML = `
                <div style="padding: 40px; text-align: center; color: var(--tg-text-secondary);">
                    <svg width="48" height="48" style="margin: 0 auto 16px; opacity: 0.5;"><use href="#icon-clipboard-list"></use></svg>
                    <p>Задач пока нет</p>
                    <p style="font-size: 13px; margin-top: 8px;">Добавьте первую задачу через поле ввода выше</p>
                </div>`;
            return;
        }

        let html = '';
        pending.forEach(t => { html += renderTaskItem(t, isManager); });
        if (completed.length > 0) {
            html += `<div class="tasks-completed-divider">Выполненные</div>`;
            completed.forEach(t => { html += renderTaskItem(t, isManager); });
        }
        container.innerHTML = html;
    } catch (error) {
        console.error('Tasks load error:', error);
        container.innerHTML = `<div style="padding: 32px; text-align: center; color: var(--tg-danger);">Ошибка: ${escapeHtml(error.message)}</div>`;
    }
}
window.loadDashboardTasks = loadDashboardTasks;

function renderTaskItem(task, isManager) {
    const isDone = task.status === 'completed';
    const priorityClass = task.priority === 'high' ? ' task-priority-high' : task.priority === 'low' ? ' task-priority-low' : '';
    const createdDate = new Date(task.created_at).toLocaleDateString('ru-RU', { day: 'numeric', month: 'short' });
    const priorityLabel = task.priority === 'high' ? '<span style="color: var(--tg-danger); font-weight: 600; font-size: 11px; margin-left: 6px;">СРОЧНО</span>' : '';

    let assigneeBadge = '';
    if (task.assigned_operator_id) {
        const opName = task.assigned_operator_name ? escapeHtml(task.assigned_operator_name) : `#${escapeHtml(task.assigned_operator_id)}`;
        assigneeBadge = `<span style="display: inline-flex; align-items: center; gap: 3px; margin-left: 6px; padding: 1px 7px; background: var(--tg-bg-secondary); border: 1px solid var(--tg-border-light); border-radius: 10px; font-size: 11px; color: var(--tg-blue); font-weight: 500;"><svg width="11" height="11" style="flex-shrink:0;"><use href="#icon-user"></use></svg>${opName}</span>`;
    }

    let metaLine = `<span>${escapeHtml(task.created_by_name || '—')}, ${createdDate}</span>`;
    if (isDone && task.completed_by_name) {
        const completedDate = new Date(task.completed_at).toLocaleDateString('ru-RU', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' });
        metaLine += ` <span style="margin-left: 8px;">— выполнил: ${escapeHtml(task.completed_by_name)}, ${completedDate}</span>`;
    }

    return `
        <div class="task-item${isDone ? ' completed' : ''}${priorityClass}">
            <button class="task-check-btn${isDone ? ' checked' : ''}" onclick="${isDone ? `reopenTask(${task.id})` : `completeTask(${task.id})`}" title="${isDone ? 'Вернуть в работу' : 'Отметить выполненной'}">
                <svg width="22" height="22"><use href="#icon-${isDone ? 'check-circle' : 'circle'}"></use></svg>
            </button>
            <div style="flex:1; min-width: 0;">
                <div class="task-title">${escapeHtml(task.title)}${priorityLabel}${assigneeBadge}</div>
                ${task.description ? `<div style="font-size: 13px; color: var(--tg-text-secondary); margin-top: 2px;">${escapeHtml(task.description)}</div>` : ''}
                <div class="task-meta">${metaLine}</div>
            </div>
            ${isManager ? `
                <button class="task-delete-btn" onclick="deleteTask(${task.id})" title="Удалить задачу">
                    <svg width="16" height="16"><use href="#icon-delete"></use></svg>
                </button>
            ` : ''}
        </div>`;
}

async function addNewTask() {
    if (!ensurePermission('tasks.manage', 'Недостаточно прав для создания задач')) return;
    const titleInput = document.getElementById('task-title-input');
    const prioritySelect = document.getElementById('task-priority-select');
    const operatorInput = document.getElementById('task-operator-input');
    if (!titleInput) return;
    const title = titleInput.value.trim();
    if (!title) {
        titleInput.focus();
        return;
    }
    const operatorId = operatorInput && operatorInput.value.trim() ? operatorInput.value.trim() : null;
    try {
        await api.createTask(title, '', prioritySelect ? prioritySelect.value : 'normal', operatorId);
        titleInput.value = '';
        if (prioritySelect) prioritySelect.value = 'normal';
        if (operatorInput) operatorInput.value = '';
        await loadDashboardTasks();
    } catch (error) {
        showError('Ошибка создания задачи: ' + error.message);
    }
}
window.addNewTask = addNewTask;

async function completeTask(id) {
    try {
        await api.completeTask(id);
        await loadDashboardTasks();
    } catch (error) {
        showError('Ошибка: ' + error.message);
    }
}
window.completeTask = completeTask;

async function reopenTask(id) {
    try {
        await api.reopenTask(id);
        await loadDashboardTasks();
    } catch (error) {
        showError('Ошибка: ' + error.message);
    }
}
window.reopenTask = reopenTask;

async function deleteTask(id) {
    if (!ensurePermission('tasks.manage', 'Недостаточно прав для удаления задач')) return;
    if (!confirm('Удалить задачу?')) return;
    try {
        await api.deleteTask(id);
        await loadDashboardTasks();
    } catch (error) {
        showError('Ошибка удаления: ' + error.message);
    }
}
window.deleteTask = deleteTask;

// =============== КОНЕЦ ЗАДАЧ ===============

// Функция для получения полного URL фото
function getPhotoUrl(photoUrl, fallbackName = 'User') {
    if (!photoUrl) {
        return `https://ui-avatars.com/api/?name=${encodeURIComponent(fallbackName)}&size=200&background=3390EC&color=fff`;
    }
    
    // Если это относительный путь (начинается с /uploads), используем текущий origin
    // Это работает потому что nginx раздает статические файлы из /uploads
    if (photoUrl.startsWith('/uploads/')) {
        // Используем window.location.origin (работает и через nginx, и напрямую)
        return `${window.location.origin}${photoUrl}`;
    }
    
    // Если это уже полный URL (http:// или https://), используем как есть
    if (photoUrl.startsWith('http://') || photoUrl.startsWith('https://')) {
        return photoUrl;
    }
    
    // Иначе используем fallback
    return `https://ui-avatars.com/api/?name=${encodeURIComponent(fallbackName)}&size=200&background=3390EC&color=fff`;
}

