async function renderShiftsTable() {
    let calendarHtml = '<div style="display: grid; grid-template-columns: repeat(7, 1fr); gap: 8px;">';
    
    // Заголовки дней недели
    const dayNames = ['Пн', 'Вт', 'Ср', 'Чт', 'Пт', 'Сб', 'Вс'];
    dayNames.forEach(day => {
        calendarHtml += `<div style="padding: 8px; text-align: center; font-weight: 600; background: var(--bg-secondary); border-radius: 4px;">${day}</div>`;
    });
    
    // Определяем первый день периода (смещение для понедельника)
    const firstDay = new Date(startDate);
    const dayOfWeek = firstDay.getDay() === 0 ? 6 : firstDay.getDay() - 1; // Понедельник = 0
    
    // Пустые ячейки до первого дня
    for (let i = 0; i < dayOfWeek; i++) {
        calendarHtml += '<div style="min-height: 100px;"></div>';
    }
    
    // Дни периода
    const currentDate = new Date(startDate);
    const todayStr = new Date().toISOString().split('T')[0];
    
    while (currentDate <= endDate) {
        const dateStr = currentDate.toISOString().split('T')[0];
        const dayShifts = shiftsByDate.get(dateStr) || [];
        const isToday = dateStr === todayStr;
        
        calendarHtml += `
            <div style="min-height: 100px; padding: 8px; border: 1px solid var(--border-color); border-radius: 4px; background: ${isToday ? 'rgba(76, 175, 80, 0.1)' : 'var(--bg-primary)'};">
                <div style="font-weight: 600; margin-bottom: 4px; ${isToday ? 'color: var(--tg-success);' : ''}">
                    ${currentDate.getDate()} ${currentDate.toLocaleDateString('ru-RU', { month: 'short' })}
                </div>
                <div style="font-size: 12px; max-height: 70px; overflow-y: auto;">
                    ${dayShifts.length === 0 ? '<div style="font-size: 11px; color: var(--tg-text-secondary);">Нет смен</div>' : ''}
                    ${dayShifts.map(shift => {
                        const shiftColors = {
                            'Дневная': '#4CAF50',
                            'Вечерняя': '#FF9800',
                            'Ночная': '#2196F3'
                        };
                        const bgColor = shiftColors[shift.shift_type] || '#9E9E9E';
                        const statusColors = {
                            'Запланирована': '#ccc',
                            'Подтверждена': '#4CAF50',
                            'Выполнена': '#2196F3',
                            'Отменена': '#f44336'
                        };
                        const statusBg = statusColors[shift.status] || '#ccc';
                        return `
                            <div style="margin-bottom: 4px; padding: 4px; background: ${bgColor}; color: white; border-radius: 3px; font-size: 11px; cursor: pointer;" 
                                 onclick="showShiftDetails(${shift.id})" 
                                 title="${escapeHtml(shift.operator_name)} - ${escapeHtml(shift.shift_type)}">
                                <div style="font-weight: 500; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">${escapeHtml(shift.operator_name)}</div>
                                <div style="font-size: 10px; opacity: 0.9;">${escapeHtml(shift.shift_type)}</div>
                                <div style="font-size: 10px; background: ${statusBg}; padding: 2px 4px; border-radius: 2px; margin-top: 2px; display: inline-block;">${escapeHtml(shift.status)}</div>
                            </div>
                        `;
                    }).join('')}
                </div>
            </div>
        `;
        
        currentDate.setDate(currentDate.getDate() + 1);
    }
    
    // Добавляем пустые ячейки до конца недели после последнего дня
    const lastDay = new Date(endDate);
    const lastDayOfWeekNum = lastDay.getDay() === 0 ? 6 : lastDay.getDay() - 1;
    const emptyCells = 6 - lastDayOfWeekNum;
    for (let i = 0; i < emptyCells; i++) {
        calendarHtml += '<div style="min-height: 100px;"></div>';
    }
    
    calendarHtml += '</div>';
    container.innerHTML = calendarHtml;
}

async function renderShiftsTable() {
    const tbody = document.getElementById('shifts-tbody');
    if (!tbody) return;
    
    if (allShiftsList.length === 0) {
        tbody.innerHTML = '<tr><td colspan="8" style="text-align: center; padding: 32px;">Нет смен за выбранный период</td></tr>';
        return;
    }
    
    // Определяем employee_id текущего пользователя, если он оператор
    const userOperatorId = await getCurrentUserOperatorId();
    const isAdminOrManager = currentUser && (currentUser.role === 'admin' || currentUser.role === 'manager');
    
    // Группируем смены по операторам
    const shiftsByOperator = new Map();
    allShiftsList.forEach(shift => {
        const operatorKey = shift.operator_id || 'unknown';
        if (!shiftsByOperator.has(operatorKey)) {
            shiftsByOperator.set(operatorKey, {
                operator_id: shift.operator_id,
                operator_name: shift.operator_name || shift.operator_id,
                shifts: []
            });
        }
        shiftsByOperator.get(operatorKey).shifts.push(shift);
    });
    
    // Сортируем смены внутри каждой группы по дате
    shiftsByOperator.forEach(operator => {
        operator.shifts.sort((a, b) => new Date(a.shift_date) - new Date(b.shift_date));
    });
    
    // Генерируем HTML с раскрывающимися списками
    let html = '';
    const operatorsArray = Array.from(shiftsByOperator.values());
    
    operatorsArray.forEach((operator, operatorIndex) => {
        const operatorId = `operator-${operatorIndex}`;
        const shiftsCount = operator.shifts.length;
        const plannedCount = operator.shifts.filter(s => s.status === 'Запланирована').length;
        const confirmedCount = operator.shifts.filter(s => s.status === 'Подтверждена').length;
        const completedCount = operator.shifts.filter(s => s.status === 'Выполнена').length;
        const totalActualHours = operator.shifts
            .filter(s => s.status === 'Выполнена' && s.actual_hours)
            .reduce((sum, s) => sum + parseFloat(s.actual_hours || 0), 0);
        
        html += `
            <tr style="background: var(--tg-bg-secondary);">
                <td colspan="8" style="padding: 12px;">
                    <details style="cursor: pointer;" id="${operatorId}" class="operator-shifts-details">
                        <summary style="display: flex; justify-content: space-between; align-items: center; list-style: none; padding: 8px; user-select: none;">
                            <div style="display: flex; align-items: center; gap: 12px; flex: 1;">
                                <svg width="16" height="16" class="chevron-icon" style="transition: transform 0.2s; flex-shrink: 0;"><use href="#icon-chevron-right"></use></svg>
                                <strong>${escapeHtml(operator.operator_name)}</strong>
                                <span style="color: var(--tg-text-secondary); font-size: 0.9em;">(${shiftsCount} ${shiftsCount === 1 ? 'смена' : shiftsCount < 5 ? 'смены' : 'смен'})</span>
                                <span style="font-size: 0.85em; color: var(--tg-text-secondary);">
                                    Запланировано: ${plannedCount}, Подтверждено: ${confirmedCount}, Выполнено: ${completedCount}
                                    ${totalActualHours > 0 ? `, Фактически отработано: ${totalActualHours.toFixed(1)} ч` : ''}
                                </span>
                            </div>
                            ${isAdminOrManager ? `
                                <button class="btn-small delete-all-shifts-btn" 
                                        data-operator-id="${escapeHtml(operator.operator_id)}" 
                                        data-operator-name="${escapeHtml(operator.operator_name)}"
                                        onclick="event.stopPropagation(); event.preventDefault();" 
                                        title="Удалить все смены оператора" 
                                        style="margin-left: 12px;">
                                    <svg width="16" height="16"><use href="#icon-delete"></use></svg>
                                    Удалить все
                                </button>
                            ` : ''}
                        </summary>
                        <div style="margin-top: 8px; padding-left: 24px;">
                            <table style="width: 100%; border-collapse: collapse;">
                                <thead>
                                    <tr style="border-bottom: 1px solid var(--tg-border);">
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Дата</th>
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Тип смены</th>
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Время</th>
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Отдел</th>
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Статус</th>
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Фактически отработано</th>
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Комментарий</th>
                                        <th style="padding: 8px; text-align: left; font-weight: 600;">Действия</th>
            </tr>
                                </thead>
                                <tbody>
                                    ${operator.shifts.map(shift => {
                                        const shiftDate = new Date(shift.shift_date);
                                        const timeDisplay = shift.start_time && shift.end_time 
                                            ? `${shift.start_time.substring(0, 5)} - ${shift.end_time.substring(0, 5)}`
                                            : '-';
                                        
                                        const statusColors = {
                                            'Запланирована': 'warning',
                                            'Подтверждена': 'info',
                                            'Выполнена': 'success',
                                            'Отменена': 'danger'
                                        };
                                        const statusBadge = statusColors[shift.status] || 'warning';
                                        
                                        // Проверяем, принадлежит ли смена текущему оператору
                                        const isMyShift = userOperatorId && shift.operator_id === userOperatorId;
                                        const canComplete = isMyShift && (shift.status === 'Запланирована' || shift.status === 'Подтверждена');
                                        
                                        let actionsHtml = '-';
                                        
                                        if (isAdminOrManager) {
                                            // Для админов и менеджеров - редактирование и удаление
                                            actionsHtml = `
                                                <button class="btn-small" onclick="showEditShiftModal(${shift.id})" title="Редактировать"><svg width="16" height="16"><use href="#icon-edit"></use></svg></button>
                                                <button class="btn-small" onclick="deleteShift(${shift.id})" title="Удалить"><svg width="16" height="16"><use href="#icon-delete"></use></svg></button>
                                            `;
                                        } else if (canComplete) {
                                            // Для операторов - кнопка завершения смены
                                            actionsHtml = `
                                                <button class="btn-small" onclick="showCompleteShiftModal(${shift.id})" title="Завершить смену"><svg width="16" height="16"><use href="#icon-check"></use></svg></button>
                                            `;
                                        } else if (isMyShift && shift.status === 'Запланирована') {
                                            // Подтверждение смены
                                            actionsHtml = `
                                                <button class="btn-small" onclick="confirmShift(${shift.id})" title="Подтвердить смену"><svg width="16" height="16"><use href="#icon-check"></use></svg></button>
                                            `;
                                        }
                                        
                                        const actualHours = shift.actual_hours ? `${shift.actual_hours} ч` : '-';
                                        
                                        return `
                                            <tr style="border-bottom: 1px solid var(--tg-border);">
                                                <td style="padding: 8px;">${shiftDate.toLocaleDateString('ru-RU')}</td>
                                                <td style="padding: 8px;">${escapeHtml(shift.shift_type)}</td>
                                                <td style="padding: 8px;">${timeDisplay}</td>
                                                <td style="padding: 8px;">${escapeHtml(shift.department || '-')}</td>
                                                <td style="padding: 8px;"><span class="badge badge-${statusBadge}">${escapeHtml(shift.status)}</span></td>
                                                <td style="padding: 8px;">${actualHours}</td>
                                                <td style="padding: 8px;">${escapeHtml(shift.comment || '-')}</td>
                                                <td style="padding: 8px; white-space: nowrap;">${actionsHtml}</td>
                                            </tr>
                                        `;
                                    }).join('')}
                                </tbody>
                            </table>
                        </div>
                    </details>
                </td>
            </tr>
        `;
    });
    
    tbody.innerHTML = html;
    
    // Добавляем обработчик для анимации иконки chevron
    operatorsArray.forEach((operator, operatorIndex) => {
        const details = document.getElementById(`operator-${operatorIndex}`);
        if (details) {
            const icon = details.querySelector('.chevron-icon');
            if (icon) {
                // Устанавливаем начальное состояние
                icon.style.transform = details.open ? 'rotate(90deg)' : 'rotate(0deg)';
                details.addEventListener('toggle', () => {
                    icon.style.transform = details.open ? 'rotate(90deg)' : 'rotate(0deg)';
                });
            }
        }
    });
    
    // Добавляем обработчики для кнопок "Удалить все"
    document.querySelectorAll('.delete-all-shifts-btn').forEach(btn => {
        btn.addEventListener('click', async function(e) {
            e.stopPropagation();
            e.preventDefault();
            const operatorId = this.getAttribute('data-operator-id');
            const operatorName = this.getAttribute('data-operator-name');
            if (operatorId && operatorName && window.deleteAllShiftsForOperator) {
                await window.deleteAllShiftsForOperator(operatorId, operatorName);
            }
        });
    });
}

async function switchShiftsTab(tabName) {
    const calendarTab = document.getElementById('shifts-calendar-tab');
    const tableTab = document.getElementById('shifts-table-tab');
    const calendarBtn = document.getElementById('shifts-tab-calendar-btn');
    const tableBtn = document.getElementById('shifts-tab-table-btn');
    
    if (tabName === 'calendar') {
        calendarTab.style.display = 'block';
        tableTab.style.display = 'none';
        calendarBtn.classList.add('active');
        tableBtn.classList.remove('active');
        renderShiftsCalendar();
    } else {
        calendarTab.style.display = 'none';
        tableTab.style.display = 'block';
        calendarBtn.classList.remove('active');
        tableBtn.classList.add('active');
        await renderShiftsTable();
    }
}

