async function updateOperator(event, id) {
    event.preventDefault();
    try {
        await api.updateOperator(id, {
            name: document.getElementById('op-edit-name').value.trim(),
            role: document.getElementById('op-edit-role').value,
            employee_id: document.getElementById('op-edit-employee-id').value.trim()
        });
        closeModal();
        await loadOperators();
        allOperators = await api.getOperators(); // Обновить глобальный список
        showSuccess('Оператор обновлён');
    } catch (error) {
        showError('Ошибка: ' + error.message);
    }
}

async function deleteOperator(id) {
    const operator = allOperatorsList.find(op => op.id === id);
    if (!operator) {
        showError('Оператор не найден');
        return;
    }
    
    const confirmed = await showConfirmModal(
        `Удалить оператора "${operator.name}"?`,
        'Удаление оператора',
        { danger: true, confirmText: 'Удалить', cancelText: 'Отмена' }
    );
    if (!confirmed) {
        return;
    }
    
    try {
        await api.deleteOperator(id);
        await loadOperators();
        allOperators = await api.getOperators(); // Обновить глобальный список
        showSuccess('Оператор удалён');
    } catch (error) {
        showError('Ошибка: ' + error.message);
    }
}

