// Функция для генерации progress bar заказа
function renderBatchProgressBars(order) {
    const bp = order.batches_progress;
    if (!Array.isArray(bp) || bp.length <= 1) return '';

    const plannedQty = order.planned_qty || 1;
    const hasExplicitSmdSides = bp.some(b => {
        if ((b.production_type || '').toUpperCase() !== 'SMD') return false;
        const side = (b.board_side || '').toString().trim().toUpperCase();
        return side === 'TOP' || side === 'BOTTOM';
    });
    const normalizedBp = hasExplicitSmdSides
        ? bp.filter(b => {
            if ((b.production_type || '').toUpperCase() !== 'SMD') return true;
            const side = (b.board_side || '').toString().trim().toUpperCase();
            return side === 'TOP' || side === 'BOTTOM';
        })
        : bp;
    const smdWithoutExplicitSide = normalizedBp
        .filter(b => (b.production_type || '').toUpperCase() === 'SMD')
        .filter(b => {
            const side = (b.board_side || '').toString().trim().toUpperCase();
            return side !== 'TOP' && side !== 'BOTTOM';
        });

    return `<div style="margin-top:4px;">` + normalizedBp.map(b => {
        const bPlanned = parseInt(b.planned_qty) || 0;
        const bActual = parseInt(b.actual_qty) || 0;
        const pct = bPlanned > 0 ? Math.round(bActual / bPlanned * 100) : 0;
        const barW = Math.min(pct, 100);
        const isOver = bActual > bPlanned;
        const color = isOver ? 'var(--tg-warning)' : pct >= 100 ? 'var(--tg-success)' : pct > 0 ? 'var(--tg-blue)' : 'var(--tg-border)';

        let label = '';
        const side = (b.board_side || '').toString().trim().toUpperCase();
        if (side === 'TOP' || side === 'ВЕРХ') {
            label = 'Верх';
        } else if (side === 'BOTTOM' || side === 'НИЗ') {
            label = 'Низ';
        } else if ((b.production_type || '').toUpperCase() === 'SMD' && smdWithoutExplicitSide.length === 2) {
            const index = smdWithoutExplicitSide.indexOf(b);
            if (index === 0) label = 'Верх';
            else if (index === 1) label = 'Низ';
            else label = b.batch_id || 'SMD';
        } else {
            label = b.production_type || b.batch_id;
        }

        const displayActual = bPlanned > 0 ? Math.round(bActual / bPlanned * plannedQty) : bActual;
        const overProduced = displayActual > plannedQty ? displayActual - plannedQty : 0;

        return `<div style="display:flex;align-items:center;gap:4px;margin-bottom:3px;font-size:10px;">
            <span style="width:30px;color:var(--tg-text-secondary);flex-shrink:0;">${escapeHtml(label)}</span>
            <div style="flex:1;height:5px;background:var(--tg-border);border-radius:3px;overflow:hidden;min-width:40px;">
                <div style="width:${barW}%;height:100%;background:${color};border-radius:3px;transition:width 0.3s;"></div>
            </div>
            <span style="width:70px;text-align:right;color:${isOver ? 'var(--tg-warning)' : pct >= 100 ? 'var(--tg-success)' : 'var(--tg-text-secondary)'};font-weight:${pct >= 100 ? '600' : '400'};flex-shrink:0;">${displayActual}/${plannedQty}${overProduced > 0 ? ` <span style="color:var(--tg-warning);">+${overProduced}</span>` : ''}</span>
        </div>`;
    }).join('') + `</div>`;
}

function renderOrderProgress(order) {
    if (!order) return '';
    
    const steps = [
        { id: 'created', label: 'Создан', status: 'Создан' },
        { id: 'production', label: 'Производство', status: 'В работе' },
        { id: 'ready-for-otk', label: 'Готов к передаче на ОТК', status: 'Готов к передаче на ОТК' }
    ];
    
    const currentStatus = order.status || 'Создан';
    let currentStepIndex = steps.findIndex(s => s.status === currentStatus);
    if (currentStepIndex === -1) currentStepIndex = 0;
    
    // Определяем прогресс (сколько шагов завершено)
    // Правильная логика: завершенными считаются только шаги ДО текущего активного
    let completedSteps = 0;
    if (currentStatus === 'Готов к передаче на ОТК') {
        // Завершены: Создан, Производство
        completedSteps = 2;
    } else if (currentStatus === 'В работе') {
        // Завершен только: Создан (производство еще идет, не завершено!)
        completedSteps = 1;
    } else {
        // Статус "Создан" - ничего не завершено, только создан
        completedSteps = 0;
    }
    
    const actualQty = order.actual_qty || 0;
    const plannedQty = order.planned_qty || 1;
    const batchesPlannedTotal = order.batches_planned_total || plannedQty;
    const progressPercent = (actualQty / batchesPlannedTotal) * 100;
    const barWidth = Math.min(progressPercent, 100);
    const displayActual = batchesPlannedTotal > plannedQty
        ? Math.round(actualQty / batchesPlannedTotal * plannedQty)
        : actualQty;
    const isOverProduced = displayActual > plannedQty;
    const overProducedQty = isOverProduced ? displayActual - plannedQty : 0;
    const displayPercent = Math.round(progressPercent * 10) / 10;
    
    const stepsHtml = steps.map((step, index) => {
        let stepClass = '';
        if (index < completedSteps) {
            stepClass = 'completed';
        } else if (index === currentStepIndex) {
            stepClass = 'active';
        }
        
        return `
            <div class="order-progress-step ${stepClass}">
                <div class="order-progress-step-icon">
                    ${index < completedSteps ? '✓' : index + 1}
                </div>
                <div class="order-progress-step-label">${escapeHtml(step.label)}</div>
            </div>
        `;
    }).join('');

    let progressColor = 'var(--tg-blue)';
    if (isOverProduced) progressColor = 'var(--tg-warning)';
    else if (progressPercent >= 100) progressColor = 'var(--tg-success)';
    
    const overProducedHtml = isOverProduced ? `
        <div style="margin-top: 10px; padding: 10px 14px; background: rgba(255, 152, 0, 0.1); border-left: 3px solid var(--tg-warning); border-radius: 4px; display: flex; align-items: center; gap: 8px;">
            <svg width="18" height="18" style="stroke: var(--tg-warning); flex-shrink: 0;"><use href="#icon-trending-up"></use></svg>
            <div>
                <span style="font-weight: 600; color: var(--tg-warning);">Перевыполнение: +${overProducedQty} шт</span>
                <span style="color: var(--tg-text-secondary); font-size: 12px; margin-left: 8px;">Произведено ${displayActual} из ${plannedQty} (${displayPercent}%)</span>
            </div>
        </div>
    ` : '';
    
    return `
        <div class="order-progress">
            <div class="order-progress-title" style="display: flex; justify-content: space-between; align-items: center;">
                <span>Прогресс выполнения заказа</span>
                <span style="font-size: 13px; font-weight: 600; color: ${progressColor};">${displayActual} / ${plannedQty} шт (${displayPercent}%)</span>
            </div>
            <div class="order-progress-steps">
                <div class="order-progress-bar" style="width: ${barWidth}%; ${isOverProduced ? 'background: var(--tg-warning);' : ''}"></div>
                ${stepsHtml}
            </div>
            ${overProducedHtml}
        </div>
    `;
}

// Функция для генерации статуса с tooltip
function renderStatusBadge(status, type = 'order', hasPausedBatches = false, hasRunningBatches = false) {
    if (!status) return '';
    
    const normalizedStatus = status.trim();
    // Пробуем найти объяснение с учетом регистра, затем без учета регистра
    let explanation = statusExplanations[normalizedStatus];
    
    // Если не нашли, пробуем найти без учета регистра (но сохраняем оригинальный регистр для отображения)
    if (!explanation) {
        const lowerStatus = normalizedStatus.toLowerCase();
        // Ищем в ключах объекта
        for (const key in statusExplanations) {
            if (key.toLowerCase() === lowerStatus) {
                explanation = statusExplanations[key];
                break;
            }
        }
    }
    
    // Определяем отображаемый статус с учетом паузы
    let displayStatus = normalizedStatus;
    let statusClass = `status-${normalizedStatus.toLowerCase().replace(/\s+/g, '-')}`;
    
    // Если заказ "В работе" и есть партии на паузе (но нет запущенных), показываем "На паузе"
    if (normalizedStatus === 'В работе' && hasPausedBatches && !hasRunningBatches) {
        displayStatus = 'На паузе';
        statusClass = 'status-на-паузе';
        // Используем объяснение для "На паузе" если есть, иначе для "В работе"
        if (!explanation || !statusExplanations['На паузе']) {
            explanation = statusExplanations['На паузе'] || explanation;
        } else {
            explanation = statusExplanations['На паузе'];
        }
    } else if (normalizedStatus === 'В работе' && hasPausedBatches && hasRunningBatches) {
        // Если есть и запущенные, и на паузе - показываем "В работе" с индикатором паузы
        displayStatus = normalizedStatus;
    }
    
    if (!explanation) {
        // Если нет объяснения, возвращаем обычный badge без tooltip
        return `<span class="status-badge ${statusClass}">${escapeHtml(displayStatus)}${hasPausedBatches && hasRunningBatches ? ' <span style="opacity: 0.7;">⏸</span>' : ''}</span>`;
    }
    
    // Формируем tooltip
    let tooltipHtml = `
        <div class="status-tooltip">
            <div class="status-tooltip-title">${escapeHtml(explanation.title)}</div>
            <div class="status-tooltip-text">${escapeHtml(explanation.description)}</div>
    `;
    
    if (explanation.action) {
        tooltipHtml += `<div class="status-tooltip-action">${escapeHtml(explanation.action)}</div>`;
    }
    
    tooltipHtml += `</div>`;
    
    return `
        <span class="status-badge-wrapper">
            <span class="status-badge ${statusClass}">${escapeHtml(displayStatus)}${hasPausedBatches && hasRunningBatches ? ' <span style="opacity: 0.7;">⏸</span>' : ''}</span>
            ${tooltipHtml}
        </span>
    `;
}

function showModal(title, content) {
    const modal = document.getElementById('modal-overlay');
    const body = document.getElementById('modal-body');
    if (!modal || !body) {
        console.error('Модальное окно не найдено!');
        showError('Модальное окно не найдено. Проверьте консоль браузера.');
        return;
    }
    body.innerHTML = `<h3>${title}</h3>${content}`;
    modal.style.display = 'flex';
    modal.classList.add('active');
}

function closeModal() {
    const modal = document.getElementById('modal-overlay');
    if (modal) {
        modal.style.display = 'none';
        modal.classList.remove('active');
    }
}

// Делаем функции глобально доступными
window.showModal = showModal;
window.closeModal = closeModal;


