window.editPlan = async function(planId) {
    try {
        // Загружаем план напрямую из API
        const plans = await api.getPlans();
        const plan = plans.find(p => p.id === planId);
        
        if (!plan) {
            showError('План не найден');
            return;
        }
        
        const products = await api.getProducts();
        const operators = await api.getOperators();
        
        const productOptions = (Array.isArray(products) ? products : []).map(p => 
            `<option value="${escapeHtml(p)}" ${p === plan.product_name ? 'selected' : ''}>${escapeHtml(p)}</option>`
        ).join('');
        
        const operatorOptions = '<option value="">-- Без оператора --</option>' + 
            (Array.isArray(operators) ? operators : []).map(op => 
                `<option value="${op.employee_id}" ${op.employee_id === plan.operator_id ? 'selected' : ''}>${escapeHtml(op.name || '')} (${op.employee_id || ''})</option>`
            ).join('');
        
        showModal('Редактировать план', `
            <form onsubmit="savePlan(event, ${planId})">
                <div class="form-group">
                    <label>Дата *</label>
                    <input type="date" id="plan-date" value="${plan.plan_date || ''}" required>
                </div>
                <div class="form-group">
                    <label>Изделие *</label>
                    <select id="plan-product" required>
                        <option value="">-- Выберите изделие --</option>
                        ${productOptions}
                    </select>
                </div>
                <div class="form-group">
                    <label>Тип производства *</label>
                    <select id="plan-production-type" required>
                        <option value="">-- Выберите тип --</option>
                        <option value="SMD" ${plan.production_type === 'SMD' ? 'selected' : ''}>SMD</option>
                        <option value="Сборка" ${plan.production_type === 'Сборка' ? 'selected' : ''}>Сборка</option>
                    </select>
                </div>
                <div class="form-group">
                    <label>Количество (шт) *</label>
                    <input type="number" id="plan-qty" min="1" value="${plan.planned_qty || 1}" required>
                </div>
                <div class="form-group">
                    <label>Оператор</label>
                    <select id="plan-operator">
                        ${operatorOptions}
                    </select>
                </div>
                <div class="form-group">
                    <label>Статус</label>
                    <select id="plan-status">
                        <option value="Запланировано" ${(plan.status || 'Запланировано') === 'Запланировано' ? 'selected' : ''}>Запланировано</option>
                        <option value="В работе" ${plan.status === 'В работе' ? 'selected' : ''}>В работе</option>
                        <option value="Выполнено" ${plan.status === 'Выполнено' ? 'selected' : ''}>Выполнено</option>
                        <option value="Отменено" ${plan.status === 'Отменено' ? 'selected' : ''}>Отменено</option>
                    </select>
                </div>
                <div class="form-group">
                    <label>Комментарий</label>
                    <textarea id="plan-comment" rows="3">${escapeHtml(plan.comment || '')}</textarea>
                </div>
                <div class="form-actions">
                    <button type="submit" class="btn">Сохранить</button>
                    <button type="button" class="btn btn-secondary" onclick="closeModal()">Отмена</button>
                </div>
            </form>
        `);
    } catch (error) {
        console.error('Ошибка загрузки плана:', error);
        showError('Ошибка: ' + error.message);
    }
};

window.savePlan = async function(event, planId) {
    event.preventDefault();
    try {
        const planDateEl = document.getElementById('plan-date');
        const planProductEl = document.getElementById('plan-product');
        const planTypeEl = document.getElementById('plan-production-type');
        const planQtyEl = document.getElementById('plan-qty');
        const planOperatorEl = document.getElementById('plan-operator');
        const planCommentEl = document.getElementById('plan-comment');
        
        if (!planDateEl || !planProductEl || !planTypeEl || !planQtyEl) {
            showError('Не все поля найдены');
            return;
        }
        
        const planData = {
            plan_date: planDateEl.value,
            product_name: planProductEl.value.trim(),
            production_type: planTypeEl.value,
            planned_qty: parseInt(planQtyEl.value) || 1,
            operator_id: planOperatorEl ? (planOperatorEl.value || null) : null,
            comment: planCommentEl ? (planCommentEl.value.trim() || null) : null
        };
        
        if (!planData.plan_date || !planData.product_name || !planData.production_type) {
            showError('Заполните все обязательные поля');
            return;
        }
        
        if (planId) {
            const planStatusEl = document.getElementById('plan-status');
            if (planStatusEl) {
                planData.status = planStatusEl.value;
            }
            await api.updatePlan(planId, planData);
            showSuccess('План обновлён');
        } else {
            await api.createPlan(planData);
            showSuccess('План создан');
        }
        
        closeModal();
        
        // Перезагружаем календарь
        await loadPlanningCalendar();
    } catch (error) {
        console.error('Ошибка сохранения плана:', error);
        showError('Ошибка: ' + error.message);
    }
};

window.deletePlanConfirm = async function(planId) {
    const confirmed = await showConfirmModal(
        'Вы уверены, что хотите удалить этот план?',
        'Удаление плана',
        { danger: true, confirmText: 'Удалить', cancelText: 'Отмена' }
    );
    if (!confirmed) {
        return;
    }
    
    try {
        await api.deletePlan(planId);
        showSuccess('План удалён');
        closeModal();
        await loadPlanningCalendar();
    } catch (error) {
        console.error('Ошибка удаления плана:', error);
        showError('Ошибка: ' + error.message);
    }
};

