async function loadInventoryComponents() {
    try {
        const components = await api.getComponents();
        const container = document.getElementById('inventory-components-list');
        if (!container) return;
        
        if (components.length === 0) {
            container.innerHTML = '<div style="padding: 32px; text-align: center; color: var(--tg-text-secondary);">Нет компонентов</div>';
            return;
        }
        
        // Группируем по категориям
        const categories = {};
        components.forEach(comp => {
            const category = comp.category || 'Разное';
            if (!categories[category]) {
                categories[category] = [];
            }
            categories[category].push(comp);
        });
        
        const sortedCategories = Object.keys(categories).sort();
        
        container.innerHTML = sortedCategories.map(category => {
            const categoryComponents = categories[category].sort((a, b) => a.name.localeCompare(b.name));
            
            return `
                <div style="margin-bottom: 24px;">
                    <h3 style="margin-bottom: 12px; font-size: 14px; font-weight: 600; color: var(--tg-text-primary); border-bottom: 1px solid var(--tg-border-light); padding-bottom: 8px;">
                        ${escapeHtml(category)}
                    </h3>
                    ${categoryComponents.map(comp => `
                        <div style="display: flex; align-items: center; gap: 12px; padding: 8px 0; border-bottom: 1px solid var(--tg-border-light);">
                            <div style="flex: 1; min-width: 0;">
                                <div style="font-weight: 500; margin-bottom: 4px;">${escapeHtml(comp.name)}${comp.unit ? ` <span style="color: var(--tg-text-secondary); font-size: 0.9em;">(${escapeHtml(comp.unit)})</span>` : ''}</div>
                                <div style="font-size: 12px; color: var(--tg-text-secondary);">Текущий остаток: ${Math.round(parseFloat(comp.stock) || 0)}${comp.unit ? ` ${escapeHtml(comp.unit)}` : ''}</div>
                            </div>
                            <div style="display: flex; align-items: center; gap: 8px;">
                                <label style="font-size: 12px; color: var(--tg-text-secondary);">Фактически:</label>
                                <input type="number" 
                                       id="inventory-${comp.id}" 
                                       value="${Math.round(parseFloat(comp.stock) || 0)}" 
                                       step="0.001" 
                                       min="0" 
                                       style="width: 100px; padding: 6px 8px; border: 1px solid var(--tg-border-light); border-radius: 4px; text-align: right;">
                            </div>
                        </div>
                    `).join('')}
                </div>
            `;
        }).join('');
    } catch (error) {
        showError('Ошибка загрузки компонентов: ' + error.message);
    }
}

window.saveInventory = async function() {
    try {
        const components = await api.getComponents();
        const updates = [];
        
        for (const comp of components) {
            const input = document.getElementById(`inventory-${comp.id}`);
            if (input) {
                const actualStock = parseFloat(input.value) || 0;
                const currentStock = parseFloat(comp.stock) || 0;
                
                if (actualStock !== currentStock) {
                    updates.push({
                        id: comp.id,
                        stock: actualStock
                    });
                }
            }
        }
        
        if (updates.length === 0) {
            showError('Нет изменений для сохранения');
            return;
        }
        
        // Обновляем все компоненты
        for (const update of updates) {
            const comp = components.find(c => c.id === update.id);
            if (comp) {
                await api.updateComponent(update.id, {
                    name: comp.name,
                    stock: update.stock,
                    unit: comp.unit || null,
                    category: comp.category || 'Разное'
                });
            }
        }
        
        showSuccess(`Инвентаризация сохранена. Обновлено ${updates.length} компонентов.`);
        closeModal();
        await loadWarehouse();
        allComponents = await api.getComponents();
    } catch (error) {
        showError('Ошибка сохранения инвентаризации: ' + error.message);
    }
}

window.exportInventoryToPDF = async function() {
    try {
        const components = await api.getComponents();
        
        if (components.length === 0) {
            showError('Нет компонентов для экспорта');
            return;
        }
        
        // Динамически загружаем jsPDF
        if (typeof window.jspdf === 'undefined') {
            const script = document.createElement('script');
            script.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
            script.onload = () => {
                exportInventoryToPDFInternal(components, false);
            };
            script.onerror = () => {
                showError('Не удалось загрузить библиотеку для экспорта PDF');
            };
            document.head.appendChild(script);
        } else {
            exportInventoryToPDFInternal(components, false);
        }
    } catch (error) {
        showError('Ошибка экспорта: ' + error.message);
    }
}

window.printInventory = async function() {
    try {
        const components = await api.getComponents();
        
        if (components.length === 0) {
            showError('Нет компонентов для печати');
            return;
        }
        
        // Собираем фактические значения из формы
        const componentsWithActual = components.map(comp => {
            const input = document.getElementById(`inventory-${comp.id}`);
            const actualStock = input ? parseFloat(input.value) || 0 : parseFloat(comp.stock) || 0;
            const currentStock = parseFloat(comp.stock) || 0;
            return {
                ...comp,
                actualStock: actualStock, // Фактическое значение из формы
                originalStock: currentStock // Учетное значение
            };
        });
        
        printInventoryInternal(componentsWithActual);
    } catch (error) {
        showError('Ошибка печати: ' + error.message);
    }
};

function printInventoryInternal(components) {
    const formatNumber = (num) => {
        if (num % 1 === 0) return num.toString();
        return num.toFixed(3).replace(/\.?0+$/, '');
    };
    
    const currentDate = new Date().toLocaleDateString('ru-RU', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });
    
    // Группируем по категориям
    const categories = {};
    components.forEach(comp => {
        const category = comp.category || 'Разное';
        if (!categories[category]) {
            categories[category] = [];
        }
        categories[category].push(comp);
    });
    
    const sortedCategories = Object.keys(categories).sort();
    
    const printContent = `
        <!DOCTYPE html>
        <html>
        <head>
            <meta charset="UTF-8">
            <title>Инвентаризация склада</title>
            <style>
                @media print {
                    @page {
                        margin: 1cm;
                    }
                    body { margin: 0; }
                    .no-print { display: none; }
                    .page-break { page-break-after: always; }
                }
                body {
                    font-family: Arial, sans-serif;
                    padding: 20px;
                    color: #000;
                }
                .header {
                    text-align: center;
                    margin-bottom: 30px;
                    border-bottom: 2px solid #000;
                    padding-bottom: 15px;
                }
                .header h1 {
                    margin: 0 0 10px 0;
                    font-size: 24px;
                }
                .header p {
                    margin: 5px 0;
                    font-size: 14px;
                    color: #666;
                }
                .category-section {
                    margin-bottom: 30px;
                }
                .category-title {
                    font-size: 16px;
                    font-weight: bold;
                    margin-bottom: 10px;
                    padding: 8px;
                    background: #f5f5f5;
                    border-left: 4px solid #000;
                }
                table {
                    width: 100%;
                    border-collapse: collapse;
                    margin-bottom: 20px;
                    font-size: 11px;
                }
                th {
                    background: #f5f5f5;
                    border: 1px solid #000;
                    padding: 8px;
                    text-align: left;
                    font-weight: bold;
                }
                td {
                    border: 1px solid #000;
                    padding: 6px;
                }
                .difference {
                    font-weight: bold;
                }
                .difference.positive {
                    color: #28a745;
                }
                .difference.negative {
                    color: #dc3545;
                }
                .footer {
                    margin-top: 30px;
                    padding-top: 15px;
                    border-top: 1px solid #000;
                    font-size: 11px;
                    color: #666;
                    text-align: center;
                }
            </style>
        </head>
        <body>
            <div class="header">
                <h1>Инвентаризация склада</h1>
                <p>Дата формирования: ${currentDate}</p>
                <p>Всего компонентов: ${components.length}</p>
            </div>
            
            ${sortedCategories.map((category, catIndex) => {
                const categoryComponents = categories[category].sort((a, b) => a.name.localeCompare(b.name));
                return `
                    <div class="category-section ${catIndex > 0 && catIndex % 3 === 0 ? 'page-break' : ''}">
                        <div class="category-title">${escapeHtml(category)} (${categoryComponents.length})</div>
                        <table>
                            <thead>
                                <tr>
                                    <th style="width: 5%;">№</th>
                                    <th style="width: 40%;">Компонент</th>
                                    <th style="width: 10%;">Ед.</th>
                                    <th style="width: 12%; text-align: right;">Учетное</th>
                                    <th style="width: 12%; text-align: right;">Фактическое</th>
                                    <th style="width: 12%; text-align: right;">Разница</th>
                                    <th style="width: 9%; text-align: center;">Статус</th>
                                </tr>
                            </thead>
                            <tbody>
                                ${categoryComponents.map((comp, index) => {
                                    const original = parseFloat(comp.originalStock) || 0;
                                    const actual = parseFloat(comp.actualStock) || 0;
                                    const diff = actual - original;
                                    const unit = comp.unit || '';
                                    const hasDifference = Math.abs(diff) > 0.001;
                                    
                                    return `
                                        <tr>
                                            <td>${index + 1}</td>
                                            <td><strong>${escapeHtml(comp.name)}</strong></td>
                                            <td>${escapeHtml(unit)}</td>
                                            <td style="text-align: right;">${formatNumber(original)}${unit ? ` ${unit}` : ''}</td>
                                            <td style="text-align: right;">${formatNumber(actual)}${unit ? ` ${unit}` : ''}</td>
                                            <td style="text-align: right;" class="difference ${diff > 0 ? 'positive' : diff < 0 ? 'negative' : ''}">
                                                ${hasDifference ? (diff > 0 ? '+' : '') + formatNumber(diff) : '0'}${unit ? ` ${unit}` : ''}
                                            </td>
                                            <td style="text-align: center;">
                                                ${hasDifference ? (diff > 0 ? '↑' : '↓') : '='}
                                            </td>
                                        </tr>
                                    `;
                                }).join('')}
                            </tbody>
                        </table>
                    </div>
                `;
            }).join('')}
            
            <div class="footer">
                <p>Сгенерировано системой CRM Production</p>
            </div>
            
            <div class="no-print" style="margin-top: 20px; text-align: center;">
                <button onclick="window.print()" style="padding: 10px 20px; font-size: 16px; cursor: pointer;">Печать</button>
                <button onclick="window.close()" style="padding: 10px 20px; font-size: 16px; cursor: pointer; margin-left: 10px;">Закрыть</button>
            </div>
        </body>
        </html>
    `;
    
    const printWindow = window.open('', '_blank');
    printWindow.document.write(printContent);
    printWindow.document.close();
    
    // Ждем загрузки и открываем диалог печати
    printWindow.onload = function() {
        setTimeout(() => {
            printWindow.print();
        }, 250);
    };
}

function exportInventoryToPDFInternal(components, isFromModal = false) {
    try {
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF();
        
        // Заголовок
        doc.setFontSize(18);
        doc.text('Инвентаризация склада', 14, 20);
        
        doc.setFontSize(10);
        doc.text(`Дата: ${new Date().toLocaleDateString('ru-RU')}`, 14, 30);
        
        // Группируем по категориям
        const categories = {};
        components.forEach(comp => {
            const category = comp.category || 'Разное';
            if (!categories[category]) {
                categories[category] = [];
            }
            categories[category].push(comp);
        });
        
        const sortedCategories = Object.keys(categories).sort();
        let yPosition = 40;
        const pageHeight = doc.internal.pageSize.height;
        const margin = 14;
        const lineHeight = 7;
        
        sortedCategories.forEach(category => {
            const categoryComponents = categories[category].sort((a, b) => a.name.localeCompare(b.name));
            
            // Проверяем, нужно ли создать новую страницу
            if (yPosition > pageHeight - 30) {
                doc.addPage();
                yPosition = margin;
            }
            
            // Заголовок категории
            doc.setFontSize(12);
            doc.setFont(undefined, 'bold');
            doc.text(category, margin, yPosition);
            yPosition += lineHeight + 2;
            
            // Таблица компонентов
            doc.setFontSize(9);
            doc.setFont(undefined, 'normal');
            
            // Заголовки таблицы
            doc.setFont(undefined, 'bold');
            if (isFromModal) {
                doc.text('Наименование', margin, yPosition);
                doc.text('Учетное', margin + 100, yPosition);
                doc.text('Фактическое', margin + 130, yPosition);
                doc.text('Ед. изм.', margin + 165, yPosition);
            } else {
                doc.text('Наименование', margin, yPosition);
                doc.text('Остаток', margin + 130, yPosition);
                doc.text('Ед. изм.', margin + 165, yPosition);
            }
            yPosition += lineHeight;
            
            // Линия под заголовками
            doc.setLineWidth(0.5);
            doc.line(margin, yPosition - 2, margin + 180, yPosition - 2);
            yPosition += 2;
            
            doc.setFont(undefined, 'normal');
            
            categoryComponents.forEach(comp => {
                // Проверяем, нужна ли новая страница
                if (yPosition > pageHeight - 20) {
                    doc.addPage();
                    yPosition = margin;
                }
                
                const stock = Math.round(parseFloat(comp.stock) || 0);
                const unit = comp.unit || '-';
                
                // Обрезаем длинные названия
                let name = comp.name;
                if (doc.getTextWidth(name) > 90) {
                    while (doc.getTextWidth(name + '...') > 90) {
                        name = name.substring(0, name.length - 1);
                    }
                    name += '...';
                }
                
                doc.text(name, margin, yPosition);
                
                if (isFromModal) {
                    // Для модального окна показываем учетное и фактическое
                    const originalStock = comp.originalStock !== undefined ? 
                        Math.round(parseFloat(comp.originalStock) || 0) : stock;
                    const actualStock = comp.actualStock !== undefined ? 
                        Math.round(parseFloat(comp.actualStock) || 0) : stock;
                    
                    doc.text(originalStock.toString(), margin + 100, yPosition);
                    doc.text(actualStock.toString(), margin + 130, yPosition);
                    doc.text(unit, margin + 165, yPosition);
                } else {
                    doc.text(stock.toString(), margin + 130, yPosition);
                    doc.text(unit, margin + 165, yPosition);
                }
                
                yPosition += lineHeight;
            });
            
            yPosition += 5; // Отступ между категориями
        });
        
        // Сохраняем PDF
        const fileName = `Инвентаризация_${new Date().toISOString().split('T')[0]}.pdf`;
        doc.save(fileName);
        
        showSuccess('Инвентаризация экспортирована в PDF');
    } catch (error) {
        console.error('Ошибка создания PDF:', error);
        showError('Ошибка создания PDF: ' + error.message);
    }
}

