// Применение режима интерфейса по пути: /otk — ОТК, /sc — СЦ, / — производство
function applyAppMode() {
    const otk = isOtkMode();
    const sc = isScMode();
    const hasOtkAccess = !currentUser || userHasPermission('otk.view', 'otk');
    const hasScAccess = !currentUser || userHasPermission('sc.view', 'sc');
    if (otk && !hasOtkAccess) {
        window.location.replace('/');
        return;
    }
    if (sc && !hasScAccess) {
        window.location.replace('/');
        return;
    }

    const specialMode = otk || sc;

    // Сайдбар: производство
    document.querySelectorAll('.sidebar li[data-mode="production"]').forEach(el => { el.style.display = specialMode ? 'none' : ''; });
    // Сайдбар: ОТК
    document.querySelectorAll('.sidebar li[data-mode="otk"]').forEach(el => {
        el.style.display = (otk && hasOtkAccess) ? '' : 'none';
    });
    // Сайдбар: СЦ
    document.querySelectorAll('.sidebar li[data-mode="sc"]').forEach(el => {
        el.style.display = (sc && hasScAccess) ? '' : 'none';
    });
    // В спец-режиме скрываем пункты производства (без data-mode или с другим data-mode)
    document.querySelectorAll('.sidebar .nav-link[data-section]').forEach(link => {
        const li = link.closest('li');
        if (!li) return;
        const mode = li.dataset.mode;
        if (otk) {
            if (mode !== 'otk') li.style.display = 'none';
        } else if (sc) {
            if (mode !== 'sc') li.style.display = 'none';
        } else {
            if (!mode || mode === 'production') li.style.display = ''; // filterNavigationByAccess уже управляет видимостью
        }
    });
    // Секции контента: OTK/SC-секции видны только в соответствующем режиме
    document.querySelectorAll('.content-section[data-mode="otk"]').forEach(sec => {
        sec.style.display = otk ? 'block' : 'none';
    });
    document.querySelectorAll('.content-section[data-mode="sc"]').forEach(sec => {
        sec.style.display = sc ? 'block' : 'none';
    });
    // При загрузке в режиме ОТК открываем «На проверке»
    if (otk) {
        const activeSection = document.querySelector('.content-section.active');
        const isOtkSection = activeSection && (activeSection.id === 'otk-pending' || activeSection.id === 'otk-ready' || activeSection.id === 'otk-regulations' || activeSection.id === 'otk-reports');
        if (!isOtkSection) {
            showSection('otk-pending');
        }
    }
    // При загрузке в режиме СЦ открываем «На исправление»
    if (sc) {
        const activeSection = document.querySelector('.content-section.active');
        const isScSection = activeSection && (activeSection.id === 'sc-pending' || activeSection.id === 'sc-completed');
        if (!isScSection) {
            showSection('sc-pending');
        }
    }
    // Мобильное меню
    document.querySelectorAll('.mobile-nav-item[data-mode-mobile="production"]').forEach(el => {
        el.style.display = specialMode ? 'none' : '';
    });
    document.querySelectorAll('.mobile-nav-item[data-mode-mobile="otk"]').forEach(el => {
        el.style.display = (otk && hasOtkAccess) ? '' : 'none';
    });
    document.querySelectorAll('.mobile-nav-item[data-mode-mobile="sc"]').forEach(el => {
        el.style.display = (sc && hasScAccess) ? '' : 'none';
    });
    // Обновляем заголовок, логотип и title
    const logoTitle = document.querySelector('.sidebar .logo h2');
    const logoSub = document.querySelector('.sidebar .logo p');
    if (logoTitle) logoTitle.textContent = 'CRM B3';
    if (logoSub) logoSub.textContent = otk ? 'ОТК' : sc ? 'Сервисный центр' : 'Производство';
    document.title = otk ? 'CRM B3 — ОТК' : sc ? 'CRM B3 — СЦ' : 'CRM B3 Производства';
}

// Фильтрация навигации по правам доступа
function filterNavigationByAccess() {
    if (!currentUser) return;

    document.querySelectorAll('.nav-link[data-section]').forEach(link => {
        const section = link.dataset.section;
        if (!section) return;

        const requiredPermission = SECTION_VIEW_PERMISSION_MAP[section];
        if (!requiredPermission) {
            link.style.display = 'flex';
            return;
        }

        link.style.display = userHasPermission(requiredPermission) ? 'flex' : 'none';
    });
}

