// Обработчик клика на дату в календаре
window.handleCalendarDateClick = function(event, dateStr) {
    // Если клик был на заказ, не создаем новый
    if (event.target.closest('div[onclick*="showOrderDetails"]')) {
        return;
    }
    // Если клик был на заголовок даты или пустое место, создаем заказ
    if (event.target.closest('.calendar-date-header') || event.target === event.currentTarget) {
        showCreateOrderModalForDate(dateStr);
    }
};

// Функция для создания заказа с предзаполненной датой (вызывается из календаря)
window.showCreateOrderModalForDate = function(dateStr) {
    showCreateOrderModal(dateStr);
};

// Функции навигации по календарю
window.changeOrdersCalendarMonth = function(delta) {
    ordersCalendarCurrentMonth += delta;
    if (ordersCalendarCurrentMonth < 0) {
        ordersCalendarCurrentMonth = 11;
        ordersCalendarCurrentYear--;
    } else if (ordersCalendarCurrentMonth > 11) {
        ordersCalendarCurrentMonth = 0;
        ordersCalendarCurrentYear++;
    }
    renderOrdersCalendar();
};

window.resetOrdersCalendarMonth = function() {
    const today = new Date();
    ordersCalendarCurrentMonth = today.getMonth();
    ordersCalendarCurrentYear = today.getFullYear();
    renderOrdersCalendar();
};

window.updateOrderPlanning = async function() {
    const productSelect = document.getElementById('order-product-select');
    const qtyInput = document.getElementById('order-planned-qty');
    const infoDiv = document.getElementById('order-planning-info');
    const contentDiv = document.getElementById('order-planning-content');
    
    if (!productSelect || !qtyInput || !infoDiv || !contentDiv) return;
    
    const productName = productSelect.value.trim();
    const plannedQty = parseInt(qtyInput.value, 10);
    
    if (!productName || !plannedQty || isNaN(plannedQty) || plannedQty < 1) {
        infoDiv.style.display = 'none';
        return;
    }
    
    try {
        infoDiv.style.display = 'block';
        contentDiv.innerHTML = '<div style="text-align: center; padding: 8px;">Расчет остатков...</div>';
        
        const demand = await api.calculateOrderDemand({
            product_name: productName,
            planned_qty: plannedQty
        });
        
        if (demand.components && demand.components.length > 0) {
            // Загружаем запасы на производстве для этих компонентов
            const componentNames = demand.components.map(c => c.component_name);
            let prodStockMap = {};
            try {
                const psData = await api.getProductionStockByNames(componentNames);
                if (Array.isArray(psData)) {
                    for (const ps of psData) {
                        prodStockMap[ps.component_name.toLowerCase().trim()] = parseFloat(ps.quantity) || 0;
                    }
                }
            } catch (e) {
                console.warn('Не удалось загрузить запасы производства:', e.message);
            }

            // Проверяем достаточность в запасах производства
            let allProdOk = true;
            let maxPossibleProd = Infinity;
            for (const c of demand.components) {
                const psQty = prodStockMap[c.component_name.toLowerCase().trim()] || 0;
                if (psQty < c.required) allProdOk = false;
                if (c.required > 0) {
                    const possibleForComp = Math.floor(psQty / (c.required / parseInt(document.getElementById('order-planned-qty')?.value || 1)));
                    maxPossibleProd = Math.min(maxPossibleProd, possibleForComp);
                }
            }
            if (maxPossibleProd === Infinity) maxPossibleProd = 0;

            let html = `
                <div style="margin-bottom: 12px; padding: 8px; background: ${allProdOk ? 'var(--tg-success-bg)' : 'var(--tg-danger-bg)'}; border-radius: 4px;">
                    <strong>${allProdOk ? '✓ Достаточно на производстве' : '✗ Недостаточно в запасах производства'}</strong>
                    ${!allProdOk ? `<br><small>Максимально можно произвести: ${maxPossibleProd} шт. Пополните запасы через «Списание» на складе.</small>` : ''}
                </div>
                <div style="max-height: 300px; overflow-y: auto;">
                    <table style="width: 100%; font-size: 0.85em; border-collapse: collapse;">
                        <thead>
                            <tr style="background: var(--tg-bg-secondary);">
                                <th style="padding: 6px; text-align: left; border-bottom: 1px solid var(--tg-border);">Компонент</th>
                                <th style="padding: 6px; text-align: right; border-bottom: 1px solid var(--tg-border);">Нужно</th>
                                <th style="padding: 6px; text-align: right; border-bottom: 1px solid var(--tg-border);">На произ-ве</th>
                                <th style="padding: 6px; text-align: right; border-bottom: 1px solid var(--tg-border);">Нехватка</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${demand.components.map(c => {
                                const psQty = prodStockMap[c.component_name.toLowerCase().trim()] || 0;
                                const psOk = psQty >= c.required;
                                const shortage = Math.max(0, c.required - psQty);
                                return `
                                <tr style="border-bottom: 1px solid var(--tg-border);">
                                    <td style="padding: 6px;">${escapeHtml(c.component_name)}</td>
                                    <td style="padding: 6px; text-align: right;">${c.required.toFixed(3)}</td>
                                    <td style="padding: 6px; text-align: right; color: ${psOk ? 'var(--tg-success)' : 'var(--tg-danger)'};">
                                        ${psQty.toFixed(3)}
                                    </td>
                                    <td style="padding: 6px; text-align: right; color: ${shortage > 0 ? 'var(--tg-danger)' : 'var(--tg-success)'};">
                                        ${shortage > 0 ? shortage.toFixed(3) : '0'}
                                    </td>
                                </tr>`;
                            }).join('')}
                        </tbody>
                    </table>
                </div>
            `;
            contentDiv.innerHTML = html;
        } else {
            contentDiv.innerHTML = '<div style="text-align: center; padding: 8px; color: var(--tg-text-secondary);">Рецептура не найдена</div>';
        }
    } catch (error) {
        console.error('Ошибка расчета планирования:', error);
        contentDiv.innerHTML = `<div style="text-align: center; padding: 8px; color: var(--tg-danger);">Ошибка: ${escapeHtml(error.message)}</div>`;
    }
};

window.createOrderSubmit = async function(event) {
    if (!ensurePermission('orders.create', 'У вас нет прав для создания заказов', 'orders')) return false;
    
    if (event) {
    event.preventDefault();
        event.stopPropagation();
    }
    
    try {
        const select = document.getElementById('order-product-select');
        
        if (!select) {
            console.error('Не найден элемент order-product-select');
            showError('Ошибка: не найдено поле выбора изделия');
            return;
        }
        
        const productName = select.value.trim();
            if (!productName) {
            showError('Выберите изделие');
            return;
        }
        
        const plannedQtyEl = document.getElementById('order-planned-qty');
        if (!plannedQtyEl || !plannedQtyEl.value) {
            showError('Введите количество');
            return;
        }
        
        const plannedQty = parseInt(plannedQtyEl.value, 10);
        if (isNaN(plannedQty) || plannedQty < 1) {
            showError('Количество должно быть положительным числом');
            return;
        }
        
        
        const orderData = {
            product_name: productName,
            planned_qty: plannedQty,
            assigned_operator_id: null, // Оператор назначается при запуске партии
            priority: document.getElementById('order-priority')?.value || 'Обычный',
            deadline: document.getElementById('order-deadline')?.value || null,
            comment: document.getElementById('order-comment')?.value || null,
        };
        
        
        const result = await api.createOrder(orderData);
        
        // Формируем детальное сообщение
        let message = result.message || 'Заказ успешно создан.';
        
        // Если есть недостающие компоненты, показываем предупреждение
        if (result.missing_components && result.missing_components.length > 0) {
            showError(`Заказ создан, но недостаточно компонентов в запасах производства:\n\n${result.missing_components.map(comp => 
                `  - ${comp.component_name}: нужно ${comp.required.toFixed(3)}, доступно ${comp.available.toFixed(3)}, недостаёт ${comp.shortage.toFixed(3)}`
            ).join('\n')}\n\nПополните запасы через «Списание» на складе → «В запасы производства».`);
        } else {
        if (result.created_batches && result.created_batches.length > 0) {
            const batchTypes = result.created_batches.map(b => b.production_type).join(', ');
            message = `Заказ успешно создан.\n\n` +
                `✓ Создано партий производства: ${result.created_batches.length} (${batchTypes})\n` +
                `✓ Компоненты списаны из запасов производства\n` +
                `✓ Статус заказа: "Создан"\n\n` +
                `Следующий шаг: Перейти в раздел "Производство" и запустить партии в работу.`;
        }
        showSuccess(message);
        }
        closeModal();
        
        // Перезагружаем список заказов
        if (typeof loadOrders === 'function') {
            await loadOrders();
        } else {
            // Если функция loadOrders не доступна, перезагружаем страницу
            setTimeout(() => window.location.reload(), 1000);
        }
    } catch (error) {
        console.error('Ошибка создания заказа:', error);
        
        // Если есть детали о недостающих компонентах - показываем их
        let errorMessage = error.message || 'Неизвестная ошибка';
        if (error.missing_components && Array.isArray(error.missing_components)) {
            errorMessage = `Недостаточно компонентов для создания заказа:\n\n${error.missing_components.map(comp => 
                `• ${comp.component_name}: нужно ${comp.required.toFixed(3)}, доступно ${comp.available.toFixed(3)}, недостаёт ${comp.shortage.toFixed(3)}`
            ).join('\n')}`;
        }
        
        showError(errorMessage);
    }
    
    return false;
};

window.showOrderDetails = async function(orderId) {
    try {
        const [order, demand] = await Promise.all([
            api.getOrder(orderId),
            api.getOrderComponentDemand(orderId).catch(() => null)
        ]);
        
        let planningHtml = '';
        if (demand && demand.components) {
            const canProduce = demand.canProduce;
            planningHtml = `
                <h3 style="margin-top: 20px; margin-bottom: 12px;">Планирование производства</h3>
                <div style="padding: 12px; background: ${canProduce ? 'var(--tg-success-bg)' : 'var(--tg-danger-bg)'}; border-radius: 4px; margin-bottom: 16px;">
                    <strong>${canProduce ? '✓ Можно произвести' : '✗ Недостаточно компонентов'}</strong>
                </div>
                <div style="max-height: 300px; overflow-y: auto;">
                    <table style="width: 100%; font-size: 0.9em; border-collapse: collapse;">
                        <thead>
                            <tr style="background: var(--tg-bg-secondary);">
                                <th style="padding: 8px; text-align: left; border-bottom: 1px solid var(--tg-border);">Компонент</th>
                                <th style="padding: 8px; text-align: right; border-bottom: 1px solid var(--tg-border);">Нужно</th>
                                <th style="padding: 8px; text-align: right; border-bottom: 1px solid var(--tg-border);">На произ-ве</th>
                                <th style="padding: 8px; text-align: right; border-bottom: 1px solid var(--tg-border);">Нехватка</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${demand.components.map(c => `
                                <tr style="border-bottom: 1px solid var(--tg-border);">
                                    <td style="padding: 8px;">${escapeHtml(c.component_name)}</td>
                                    <td style="padding: 8px; text-align: right;">${c.required.toFixed(3)}</td>
                                    <td style="padding: 8px; text-align: right; color: ${c.available >= c.required ? 'var(--tg-success)' : 'var(--tg-danger)'};">
                                        ${c.available.toFixed(3)}
                                    </td>
                                    <td style="padding: 8px; text-align: right; color: ${c.shortage > 0 ? 'var(--tg-danger)' : 'var(--tg-success)'};">
                                        ${c.shortage > 0 ? c.shortage.toFixed(3) : '0'}
                                    </td>
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>
                </div>
            `;
        }
        
        // Генерируем progress bar
        const progressHtml = renderOrderProgress(order);
        
        // Формируем ссылки на партии
        const batchesHtml = order.batches && order.batches.length > 0 ? 
            order.batches.map(b => {
                const batchId = escapeHtml(b.batch_id);
                return `
                    <tr style="cursor: pointer;" onclick="showProductionBatchDetails('${batchId.replace(/'/g, "\\'")}')">
                        <td>
                            <a href="#" class="related-link" onclick="event.stopPropagation(); showProductionBatchDetails('${batchId.replace(/'/g, "\\'")}'); return false;">
                                ${batchId}
                                <svg width="14" height="14"><use href="#icon-eye"></use></svg>
                            </a>
                        </td>
                        <td>${escapeHtml(b.production_type)}</td>
                        <td>${b.planned_qty}</td>
                        <td style="${(b.actual_qty || 0) > b.planned_qty ? 'color: var(--tg-warning); font-weight: 600;' : ''}">${b.actual_qty || 0}${(b.actual_qty || 0) > b.planned_qty ? ` <span style="font-size: 0.8em;">(+${(b.actual_qty || 0) - b.planned_qty})</span>` : ''}</td>
                        <td>${renderStatusBadge(b.status, 'production')}</td>
                    </tr>
                `;
            }).join('') : 
            '<tr><td colspan="5" style="text-align: center; padding: 16px; color: var(--tg-text-secondary);">Партии производства еще не созданы</td></tr>';
        
        // Информация о заказе на восстановление
        const isRepairOrder = order.order_type === 'repair';
        const repairInfoHtml = isRepairOrder ? `
            <div style="margin-bottom: 20px; padding: 16px; background: rgba(255, 193, 7, 0.1); border-left: 4px solid var(--tg-warning); border-radius: 4px;">
                <div style="display: flex; align-items: center; gap: 8px; margin-bottom: 12px;">
                    <svg width="20" height="20" style="stroke: var(--tg-warning);"><use href="#icon-settings"></use></svg>
                    <strong style="color: var(--tg-warning); font-size: 1.1em;">Заказ на восстановление брака</strong>
                </div>
                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 8px; font-size: 0.9em;">
                    ${order.source_order_id ? `<div><strong>Исходный заказ:</strong> #${order.source_order_id}</div>` : ''}
                    ${order.source_otk_batch_id ? `<div><strong>Исходная партия ОТК:</strong> #${order.source_otk_batch_id}</div>` : ''}
                    <div><strong>Брак на восстановление:</strong> ${order.repair_defect_qty || order.planned_qty} шт</div>
                    <div><strong>Восстановлено:</strong> ${order.actual_qty || 0} шт</div>
                </div>
                ${order.status !== 'Передан на ОТК' && order.actual_qty > 0 ? `
                    <div style="margin-top: 12px;">
                        <button class="btn" onclick="showReturnRepairedDefectModal(${order.id})" style="background: var(--tg-success); color: white;">
                            <svg width="16" height="16" style="vertical-align: middle; margin-right: 4px; stroke: white;"><use href="#icon-check"></use></svg>
                            Вернуть восстановленный брак в систему
                        </button>
                    </div>
                ` : ''}
            </div>
        ` : '';
        
        const orderActual = order.actual_qty || 0;
        const orderPlanned = order.planned_qty || 0;
        const orderBatchesPlanned = order.batches_planned_total || orderPlanned;
        const orderDisplayActual = orderBatchesPlanned > orderPlanned
            ? Math.round(orderActual / orderBatchesPlanned * orderPlanned)
            : orderActual;
        const orderIsOverProduced = orderDisplayActual > orderPlanned && orderPlanned > 0;
        const orderOverQty = orderIsOverProduced ? orderDisplayActual - orderPlanned : 0;
        const orderPct = orderBatchesPlanned > 0 ? Math.round(orderActual / orderBatchesPlanned * 1000) / 10 : 0;
        
        showModal(`Заказ #${order.id}: ${escapeHtml(order.product_name)}${isRepairOrder ? ' 🔧 Восстановление' : ''}`, `
            ${repairInfoHtml}
            <div style="margin-bottom: 20px;">
                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 12px; font-size: 0.95em;">
                    <div><strong>Изделие:</strong> ${escapeHtml(order.product_name)}</div>
                    <div><strong>Количество:</strong> ${order.planned_qty} шт${orderDisplayActual > 0 ? ` <span style="color: ${orderIsOverProduced ? 'var(--tg-warning)' : 'var(--tg-success)'}; font-weight: 600;">(факт: ${orderDisplayActual} шт, ${orderPct}%)</span>` : ''}</div>
                    <div><strong>Статус:</strong> ${renderStatusBadge(order.status, 'order')}</div>
                    <div><strong>Приоритет:</strong> <span class="badge badge-${order.priority === 'Срочный' ? 'danger' : order.priority === 'Высокий' ? 'warning' : 'info'}">${escapeHtml(order.priority)}</span></div>
                    ${order.deadline ? `<div><strong>Срок:</strong> ${new Date(order.deadline).toLocaleDateString('ru-RU')}</div>` : ''}
                    ${order.assigned_operator_name ? `<div><strong>Исполнитель:</strong> ${escapeHtml(order.assigned_operator_name)}</div>` : ''}
                    ${order.comment ? `<div style="grid-column: 1 / -1;"><strong>Комментарий:</strong> ${escapeHtml(order.comment)}</div>` : ''}
                </div>
            </div>
            ${progressHtml}
            ${planningHtml}
            <h3 style="margin-top: 20px; margin-bottom: 12px;">Партии производства:</h3>
            <div style="max-height: 300px; overflow-y: auto;">
                <table style="width: 100%; font-size: 0.9em; border-collapse: collapse;">
                    <thead>
                        <tr style="background: var(--tg-bg-secondary); border-bottom: 2px solid var(--tg-border);">
                            <th style="padding: 8px; text-align: left;">ID партии</th>
                            <th style="padding: 8px; text-align: left;">Тип</th>
                            <th style="padding: 8px; text-align: right;">Планируется</th>
                            <th style="padding: 8px; text-align: right;">Факт</th>
                            <th style="padding: 8px; text-align: left;">Статус</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${batchesHtml}
                    </tbody>
                </table>
            </div>
        `);
    } catch (error) {
        showError('Ошибка: ' + error.message);
    }
};

// Модальное окно для возврата восстановленного брака
window.showReturnRepairedDefectModal = async function(repairOrderId) {
    try {
        const order = await api.getOrder(repairOrderId);
        
        if (!order || order.order_type !== 'repair') {
            showError('Это не заказ на восстановление');
            return;
        }
        
        const maxReturnQty = order.actual_qty || 0;
        const alreadyReturned = order.actual_qty || 0;
        const totalRepairQty = order.repair_defect_qty || order.planned_qty;
        const remainingToReturn = totalRepairQty - alreadyReturned;
        
        if (maxReturnQty <= 0) {
            showError('Нет восстановленного брака для возврата');
            return;
        }
        
        showModal('Вернуть восстановленный брак в систему', `
            <form onsubmit="returnRepairedDefectSubmit(event, ${repairOrderId})">
                <div style="margin-bottom: 16px; padding: 16px; background: var(--tg-bg-secondary); border-radius: 8px;">
                    <p style="margin: 8px 0 0 0;"><strong>Изделие:</strong> ${escapeHtml(order.product_name)}</p>
                    <p style="margin: 8px 0 0 0;"><strong>Брак на восстановление:</strong> ${totalRepairQty} шт</p>
                    <p style="margin: 8px 0 0 0;"><strong>Восстановлено:</strong> ${alreadyReturned} шт</p>
                    <p style="margin: 8px 0 0 0;"><strong>Осталось вернуть:</strong> ${remainingToReturn} шт</p>
                </div>
                <div class="form-group">
                    <label>Количество восстановленного брака для возврата *</label>
                    <input type="number" id="return-repaired-qty" required min="1" max="${maxReturnQty}" value="${maxReturnQty}">
                    <small style="color: var(--tg-text-secondary);">Можно вернуть до ${maxReturnQty} шт</small>
                </div>
                <div style="padding: 12px; background: rgba(76, 175, 80, 0.1); border-left: 3px solid var(--tg-success); border-radius: 4px; margin-bottom: 16px;">
                    <strong style="color: var(--tg-success);">Что произойдет:</strong>
                    <ul style="margin: 8px 0 0 0; padding-left: 20px; font-size: 0.9em;">
                        <li>Восстановленный брак вернется в исходную партию ОТК</li>
                        <li>Количество годных изделий в исходной партии увеличится</li>
                        <li>Заказ на восстановление обновится</li>
                    </ul>
                </div>
                <div class="form-actions">
                    <button type="button" class="btn btn-secondary" onclick="closeModal()">Отмена</button>
                    <button type="submit" class="btn" style="background: var(--tg-success); color: white;">Вернуть в систему</button>
                </div>
            </form>
        `);
    } catch (error) {
        showError('Ошибка загрузки данных: ' + error.message);
    }
};

window.returnRepairedDefectSubmit = async function(event, repairOrderId) {
    event.preventDefault();
    
    try {
        const repairedQty = parseInt(document.getElementById('return-repaired-qty').value);
        
        if (!repairedQty || repairedQty <= 0) {
            showError('Укажите количество восстановленного брака');
            return;
        }
        
        await api.returnRepairedDefect(repairOrderId, repairedQty);
        showSuccess('Восстановленный брак успешно возвращен в систему');
        closeModal();
        await loadOrders();
        await loadDashboard();
    } catch (error) {
        showError('Ошибка возврата восстановленного брака: ' + error.message);
    }
};

window.showEditOrderModal = async function(orderId) {
    try {
        const [order, allProducts] = await Promise.all([
            api.getOrder(orderId),
            api.getProducts().catch(err => {
                console.error('Ошибка загрузки изделий:', err);
                return [];
            })
        ]);
        
        // API возвращает массив строк (названий продуктов)
        const uniqueProducts = [...new Set(allProducts)].sort();
        const currentProductExists = uniqueProducts.includes(order.product_name);
        
        showModal('Редактировать заказ', `
            <form onsubmit="updateOrderSubmit(event, ${orderId}); return false;">
                <div class="form-group">
                    <label>Изделие:</label>
                    <select id="order-product-select" onchange="toggleOrderEditProductInput()" style="margin-bottom: 8px;">
                        <option value="">-- Выберите из списка --</option>
                        <option value="__new__" ${!currentProductExists ? 'selected' : ''}>+ Создать новое изделие</option>
                        ${uniqueProducts.map(p => `<option value="${escapeHtml(p)}" ${p === order.product_name ? 'selected' : ''}>${escapeHtml(p)}</option>`).join('')}
                    </select>
                    <input type="text" id="order-product-name" value="${escapeHtml(order.product_name)}" required style="display: ${currentProductExists ? 'none' : 'block'};">
                </div>
                <div class="form-group">
                    <label>Количество:</label>
                    <input type="number" id="order-planned-qty" value="${order.planned_qty}" required min="1">
                </div>
                <div class="form-group">
                    <label>Приоритет:</label>
                    <select id="order-priority">
                        <option value="Обычный" ${order.priority === 'Обычный' ? 'selected' : ''}>Обычный</option>
                        <option value="Высокий" ${order.priority === 'Высокий' ? 'selected' : ''}>Высокий</option>
                        <option value="Срочный" ${order.priority === 'Срочный' ? 'selected' : ''}>Срочный</option>
                    </select>
                </div>
                <div class="form-group">
                    <label>Срок:</label>
                    <input type="date" id="order-deadline" value="${order.deadline ? order.deadline.split('T')[0] : ''}">
                </div>
                <div class="form-group">
                    <label>Статус:</label>
                    <select id="order-status">
                        <option value="Создан" ${order.status === 'Создан' ? 'selected' : ''}>Создан</option>
                        <option value="В работе" ${order.status === 'В работе' ? 'selected' : ''}>В работе</option>
                        <option value="Готов к передаче на ОТК" ${order.status === 'Готов к передаче на ОТК' ? 'selected' : ''}>Готов к передаче на ОТК</option>
                        <option value="Передан на ОТК" ${order.status === 'Передан на ОТК' ? 'selected' : ''}>Передан на ОТК</option>
                        <option value="Завершен" ${order.status === 'Завершен' ? 'selected' : ''}>Завершен</option>
                        <option value="Отменен" ${order.status === 'Отменен' ? 'selected' : ''}>Отменен</option>
                    </select>
                </div>
                <div class="form-group">
                    <label>Комментарий:</label>
                    <textarea id="order-comment" rows="3">${escapeHtml(order.comment || '')}</textarea>
                </div>
                <div class="form-group">
                    <button type="button" class="btn btn-small btn-secondary" onclick="closeModal(); showEditOrderPlanModal(${orderId})">Редактировать план (распределение по дням)</button>
                </div>
                <div class="form-actions">
                    <button type="button" class="btn btn-secondary" onclick="closeModal()">Отмена</button>
                    <button type="submit" class="btn">Сохранить</button>
                </div>
            </form>
            <script>
                window.toggleOrderEditProductInput = function() {
                    const select = document.getElementById('order-product-select');
                    const input = document.getElementById('order-product-name');
                    if (select.value === '__new__') {
                        input.style.display = 'block';
                        input.required = true;
                        select.required = false;
                        input.focus();
                    } else if (select.value) {
                        input.style.display = 'none';
                        input.required = false;
                        input.value = select.value;
                    } else {
                        input.style.display = 'none';
                        input.required = false;
                        input.value = '';
                    }
                };
            </script>
        `);
    } catch (error) {
        showError('Ошибка: ' + error.message);
    }
};

window.updateOrderSubmit = async function(event, orderId) {
    event.preventDefault();
    
    const submitBtn = event.target.querySelector('button[type="submit"]') || 
                     document.querySelector('.modal-content button[type="submit"]');
    setButtonLoading(submitBtn, true);
    
    try {
        const select = document.getElementById('order-product-select');
        const input = document.getElementById('order-product-name');
        let productName;
        
        if (select.value === '__new__') {
            productName = input.value.trim();
            if (!productName) {
                showError('Введите название изделия');
                setButtonLoading(submitBtn, false);
                return;
            }
        } else if (select.value) {
            productName = select.value;
        } else {
            // Если выбран существующий в select, но input скрыт
            productName = input.value.trim() || select.value;
        }
        
        if (!productName) {
            showError('Выберите изделие или создайте новое');
            setButtonLoading(submitBtn, false);
            return;
        }
        
        await api.updateOrder(orderId, {
            product_name: productName,
            planned_qty: parseInt(document.getElementById('order-planned-qty').value),
            priority: document.getElementById('order-priority').value,
            deadline: document.getElementById('order-deadline').value || null,
            status: document.getElementById('order-status').value,
            comment: document.getElementById('order-comment').value || null
        });
        
        showSuccess('Заказ обновлен');
        closeModal();
        await loadOrders();
    } catch (error) {
        showError('Ошибка: ' + error.message);
    } finally {
        setButtonLoading(submitBtn, false);
    }
};

window.startOrder = async function(orderId) {
    if (!ensurePermission('orders.start', 'Недостаточно прав для запуска заказа', 'orders')) return;
    const allowed = await ensureChecklistBeforeProductionStart();
    if (!allowed) return;

    // Проверяем доступность компонентов перед подтверждением
    try {
        const demand = await api.getOrderComponentDemand(orderId);
        if (!demand.canProduce) {
            const missingComponents = demand.components.filter(c => c.shortage > 0);
            const missingInfo = missingComponents.map(c => 
                `  - ${c.component_name}: нужно ${c.required.toFixed(3)}, доступно ${c.available.toFixed(3)}, недостаёт ${c.shortage.toFixed(3)}`
            ).join('\n');
            
            showError(`Недостаточно компонентов для запуска заказа:\n\n${missingInfo}\n\nПополните склад и попробуйте снова.`);
            await loadOrders(); // Обновляем список, чтобы обновить статус кнопки
        return;
    }
    } catch (error) {
        console.error('Ошибка проверки компонентов:', error);
        // Продолжаем, если проверка не удалась
    }

    // Подтверждаем действие
    const confirmed = await showConfirmModal(
        'Перевести заказ в работу?\n\nОператор будет назначен при запуске партий производства в разделе "Производство".',
        'Перевод заказа в работу',
        { confirmText: 'Перевести в работу', cancelText: 'Отмена' }
    );
    
    if (!confirmed) {
        return;
    }
    
    // Показываем индикатор загрузки
    const loading = showLoading('Перевод заказа в работу...', true);
    
    try {
        // Переводим заказ в работу без назначения оператора
        // Оператор будет назначен при запуске партий производства
        await api.startOrder(orderId, null);
        hideLoading(loading);
        showSuccess('Заказ переведен в работу');
        
        // Оптимистичное обновление - обновляем параллельно
        await Promise.all([
            loadOrders(),
            loadProduction() // Обновляем производство, чтобы показать заказ
        ]);
    } catch (error) {
        hideLoading(loading);
        // Если ошибка связана с недостатком компонентов, показываем детальную информацию
        let errorMessage = error.message;
        try {
            const errorData = JSON.parse(error.message);
            if (errorData.missing_components) {
                const missingInfo = errorData.missing_components.map(c => 
                    `  - ${c.component_name}: нужно ${c.required.toFixed(3)}, доступно ${c.available.toFixed(3)}, недостаёт ${c.shortage.toFixed(3)}`
                ).join('\n');
                errorMessage = `Недостаточно компонентов для запуска заказа:\n\n${missingInfo}`;
            }
        } catch (e) {
            // Если не удалось распарсить, используем исходное сообщение
        }
        showError(errorMessage);
        await loadOrders(); // Обновляем список, чтобы обновить статус кнопки
    }
};

// Запустить заказ оператором (из раздела "Мои заказы")
window.startMyOrder = async function(orderId) {
    try {
        if (!ensurePermission('orders.start', 'Недостаточно прав для запуска заказа', 'orders')) return;
        const allowed = await ensureChecklistBeforeProductionStart();
        if (!allowed) return;

        // Получаем информацию о заказе и его партиях
        const batches = await api.getProductionBatches();
        const orderBatches = batches.filter(b => b.order_id === orderId && b.status === 'Запланировано');
        
        if (orderBatches.length === 0) {
            showError('Нет запланированных партий для этого заказа');
            return;
        }
        
        // Берем первую партию
        const firstBatch = orderBatches[0];
        
        // Получаем текущего пользователя (оператора)
        if (!currentUser) {
            showError('Не удалось определить оператора');
            return;
        }
        
        // Получаем employee_id оператора
        const operators = await api.getOperators();
        const userName = currentUser.full_name || currentUser.username;
        const operator = operators.find(op => op.name === userName);
        
        if (!operator || !operator.employee_id) {
            showError('Оператор не найден');
            return;
        }
        
        // Запускаем первую партию
        const loading = showLoading('Запуск производства...', true);
        try {
            await api.startBatchById(firstBatch.batch_id, [operator.employee_id]);
            hideLoading(loading);
            showSuccess('Приятной работы! 🎉');
            
            // Обновляем данные
            await Promise.all([
                loadMyOrders(),
                loadProduction(),
                loadDashboard()
            ]);
        } catch (error) {
            hideLoading(loading);
            showError('Ошибка запуска партии: ' + error.message);
        }
    } catch (error) {
        showError('Ошибка: ' + error.message);
    }
};

