// Загрузка графика смен сотрудников
async function loadShiftSchedule() {
    try {
        const container = document.getElementById('shift-schedule-container');
        if (!container) return;
        
        if (mountingOperators.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align: center; padding: 32px; color: var(--tg-text-secondary);">Нет установщиков</td></tr>';
            return;
        }
        
        tbody.innerHTML = mountingOperators.map(mo => {
            const projects = mo.projects && Array.isArray(mo.projects) && mo.projects.length > 0
                ? mo.projects.map(p => escapeHtml(p.project_code || p.project_name || '')).join(', ')
                : mo.can_work_all_projects ? 'Все проекты' : 'Не назначены';
            
            return `
                <tr>
                    <td>${mo.line_number ? `Линия ${mo.line_number}` : '-'}${mo.line_name ? ` (${escapeHtml(mo.line_name)})` : ''}</td>
                    <td>Позиция ${mo.position_number}</td>
                    <td>${mo.operator_name ? escapeHtml(mo.operator_name) : '-'}</td>
                    <td>${projects}</td>
                    <td>
                        <span class="badge badge-${mo.is_active ? 'success' : 'secondary'}">
                            ${mo.is_active ? 'Активен' : 'Неактивен'}
                        </span>
                    </td>
                    <td style="white-space: nowrap;">
                        <button class="btn-small" onclick="showEditMountingOperatorModal(${mo.id})" title="Редактировать">
                            <svg width="16" height="16"><use href="#icon-edit"></use></svg>
                        </button>
                        <button class="btn-small" onclick="deleteMountingOperator(${mo.id})" title="Удалить" style="color: var(--tg-danger);">
                            <svg width="16" height="16"><use href="#icon-delete"></use></svg>
                        </button>
                    </td>
                </tr>
            `;
        }).join('');
    } catch (error) {
        console.error('Ошибка загрузки установщиков:', error);
        const tbody = document.getElementById('mounting-operators-tbody');
        if (tbody) {
            tbody.innerHTML = `<tr><td colspan="6" style="text-align: center; padding: 32px; color: var(--tg-danger);">Ошибка: ${escapeHtml(error.message)}</td></tr>`;
        }
    }
}

// Загрузка линий производства
async function loadSMDLines() {
    try {
        const tbody = document.getElementById('smd-lines-tbody');
        if (!tbody) return;
        
        tbody.innerHTML = '<tr><td colspan="5">Загрузка...</td></tr>';
        
        const lines = await api.getSMDLines();
        
        if (lines.length === 0) {
            tbody.innerHTML = '<tr><td colspan="5" style="text-align: center; padding: 32px; color: var(--tg-text-secondary);">Нет линий производства</td></tr>';
            return;
        }
        
        tbody.innerHTML = lines.map(line => {
            const mountingOperatorsCount = line.mounting_operators_count || 0;
            
            return `
                <tr>
                    <td>${line.line_number || '-'}</td>
                    <td>${line.line_name ? escapeHtml(line.line_name) : '-'}</td>
                    <td>${mountingOperatorsCount}</td>
                    <td>
                        <span class="badge badge-${line.is_active ? 'success' : 'secondary'}">
                            ${line.is_active ? 'Активна' : 'Неактивна'}
                        </span>
                    </td>
                    <td style="white-space: nowrap;">
                        <button class="btn-small" onclick="showEditSMDLineModal(${line.id})" title="Редактировать">
                            <svg width="16" height="16"><use href="#icon-edit"></use></svg>
                        </button>
                    </td>
                </tr>
            `;
        }).join('');
    } catch (error) {
        console.error('Ошибка загрузки линий:', error);
        const tbody = document.getElementById('smd-lines-tbody');
        if (tbody) {
            tbody.innerHTML = `<tr><td colspan="5" style="text-align: center; padding: 32px; color: var(--tg-danger);">Ошибка: ${escapeHtml(error.message)}</td></tr>`;
        }
    }
}

